var QUESTIONS_THEORY_7 = [
{type:"mcq",diff:"easy",en:{q:"Which of the following describes a spreadsheet application like MS Excel?",opts:["A software for creating graphics and animations","An electronic document storing data in rows and columns","A system utility for disk defragmentation","A program exclusively for sending emails"],ans:1,exp:"MS Excel is a powerful spreadsheet application used primarily for data management, financial analysis, and complex computations. It utilizes a grid of rows and columns to organize data logically. Users can apply advanced formulas, create graphical charts, and automate tasks through macros to enhance productivity and decision-making."},hi:{q:"निम्नलिखित में से कौन MS Excel जैसे स्प्रेडशीट एप्लिकेशन का वर्णन करता है?",opts:["ग्राफिक्स और एनिमेशन बनाने के लिए एक सॉफ्टवेयर","एक इलेक्ट्रॉनिक दस्तावेज़ जो डेटा को पंक्तियों और कॉलम में संग्रहीत करता है","डिस्क डीफ़्रेग्मेंटेशन के लिए एक सिस्टम उपयोगिता","विशेष रूप से ईमेल भेजने के लिए एक प्रोग्राम"],ans:1,exp:"MS Excel एक शक्तिशाली स्प्रेडशीट एप्लिकेशन है जिसका उपयोग मुख्य रूप से डेटा प्रबंधन, वित्तीय विश्लेषण और जटिल गणनाओं के लिए किया जाता है। यह डेटा को तार्किक रूप से व्यवस्थित करने के लिए पंक्तियों और कॉलम के ग्रिड का उपयोग करता है। उपयोगकर्ता उत्पादकता और निर्णय लेने को बढ़ाने के लिए उन्नत सूत्र लागू कर सकते हैं, ग्राफिकल चार्ट बना सकते हैं और मैक्रोज़ के माध्यम से कार्यों को स्वचालित कर सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What is the default name given to a newly created workbook in MS Excel?",opts:["Spreadsheet1","Document1","Book1","Worksheet1"],ans:2,exp:"When a user launches MS Excel and opens a new file, the application assigns a default temporary name called 'Book1'. This workbook can contain multiple worksheets (like Sheet1, Sheet2). The user must manually save the file with a desired, specific name to prevent data loss and ensure proper file organization on the storage drive."},hi:{q:"MS Excel में नए बनाए गए वर्कबुक को दिया गया डिफ़ॉल्ट नाम क्या है?",opts:["Spreadsheet1","Document1","Book1","Worksheet1"],ans:2,exp:"जब कोई उपयोगकर्ता MS Excel लॉन्च करता है और एक नई फ़ाइल खोलता है, तो एप्लिकेशन 'Book1' नामक एक डिफ़ॉल्ट अस्थायी नाम निर्दिष्ट करता है। इस वर्कबुक में कई वर्कशीट (जैसे Sheet1, Sheet2) हो सकते हैं। डेटा हानि को रोकने और स्टोरेज ड्राइव पर उचित फ़ाइल संगठन सुनिश्चित करने के लिए उपयोगकर्ता को वांछित, विशिष्ट नाम के साथ फ़ाइल को मैन्युअल रूप से सहेजना होगा।"}},
{type:"mcq",diff:"easy",en:{q:"Every formula or function in MS Excel must begin with which of the following symbols?",opts:["@ (At the rate)","# (Hash)","+ (Plus)","= (Equal to)"],ans:3,exp:"MS Excel uses the equal sign (=) to denote the beginning of a formula or a function. If the equal sign is omitted, Excel treats the input as standard text or a static numerical value, preventing any mathematical operations. This essential syntax rule ensures that the calculation engine processes the cell contents correctly."},hi:{q:"MS Excel में प्रत्येक सूत्र या फ़ंक्शन निम्नलिखित में से किस प्रतीक से शुरू होना चाहिए?",opts:["@ (एट द रेट)","# (हैश)","+ (प्लस)","= (बराबर)"],ans:3,exp:"MS Excel सूत्र या फ़ंक्शन की शुरुआत को दर्शाने के लिए बराबर चिह्न (=) का उपयोग करता है। यदि बराबर चिह्न छोड़ दिया जाता है, तो Excel इनपुट को मानक टेक्स्ट या स्थिर संख्यात्मक मान के रूप में मानता है, जिससे कोई भी गणितीय संचालन नहीं हो पाता है। यह आवश्यक सिंटैक्स नियम सुनिश्चित करता है कि गणना इंजन सेल सामग्री को सही ढंग से संसाधित करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the fundamental difference between a Workbook and a Worksheet in MS Excel?",opts:["A workbook is a single page, while a worksheet contains many workbooks","A workbook is the entire file containing one or more worksheets","They are two different names for the exact same thing","A worksheet is used for text, and a workbook is used for numbers"],ans:1,exp:"A Workbook in Excel is the actual file (usually with an .xlsx extension) that you save on your computer. Inside a single workbook, you can have multiple Worksheets, which are the individual grids of rows and columns where you enter data. This hierarchical structure allows related datasets to be grouped together within one master file."},hi:{q:"MS Excel में वर्कबुक और वर्कशीट के बीच मूल अंतर क्या है?",opts:["वर्कबुक एक पृष्ठ है, जबकि वर्कशीट में कई वर्कबुक होते हैं","एक वर्कबुक पूरी फ़ाइल है जिसमें एक या अधिक वर्कशीट होते हैं","वे बिल्कुल एक ही चीज़ के दो अलग-अलग नाम हैं","वर्कशीट का उपयोग टेक्स्ट के लिए होता है, और वर्कबुक का संख्याओं के लिए"],ans:1,exp:"Excel में वर्कबुक वास्तविक फ़ाइल (आमतौर पर .xlsx एक्सटेंशन के साथ) है जिसे आप अपने कंप्यूटर पर सहेजते हैं। एक ही वर्कबुक के अंदर, आपके पास कई वर्कशीट हो सकते हैं, जो पंक्तियों और कॉलम के व्यक्तिगत ग्रिड होते हैं जहां आप डेटा दर्ज करते हैं। यह पदानुक्रमित संरचना संबंधित डेटासेट को एक मास्टर फ़ाइल के भीतर समूहीकृत करने की अनुमति देती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is the standard file extension for an MS Excel 2010 (and later) workbook?",opts:[".xls",".xlsx",".docx",".csv"],ans:1,exp:"Starting with MS Office 2007 and continuing through 2010 and beyond, Microsoft adopted the Office Open XML format. The standard file extension for an Excel workbook became '.xlsx', replacing the older proprietary '.xls' binary format. This new XML-based format offers better file compression, improved security, and robust data recovery features."},hi:{q:"MS Excel 2010 (और बाद के) वर्कबुक के लिए मानक फ़ाइल एक्सटेंशन निम्नलिखित में से कौन सा है?",opts:[".xls",".xlsx",".docx",".csv"],ans:1,exp:"MS Office 2007 से शुरू होकर और 2010 और उसके बाद भी, Microsoft ने Office Open XML प्रारूप अपनाया। Excel वर्कबुक के लिए मानक फ़ाइल एक्सटेंशन '.xlsx' बन गया, जिसने पुराने मालिकाना '.xls' बाइनरी प्रारूप को बदल दिया। यह नया XML-आधारित प्रारूप बेहतर फ़ाइल संपीड़न, उन्नत सुरक्षा और मजबूत डेटा पुनर्प्राप्ति सुविधाएँ प्रदान करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What term is used to describe the intersection of a single row and a single column in MS Excel?",opts:["Grid","Box","Cell","Range"],ans:2,exp:"In a spreadsheet, the intersection of a horizontal row and a vertical column is called a 'Cell'. Each cell is identified by a unique reference address containing its column letter and row number (e.g., A1, B5). A cell is the basic unit for storing data, text, or formulas in Microsoft Excel."},hi:{q:"MS Excel में एकल पंक्ति और एकल कॉलम के प्रतिच्छेदन का वर्णन करने के लिए किस शब्द का उपयोग किया जाता है?",opts:["ग्रिड","बॉक्स","सेल","रेंज"],ans:2,exp:"एक स्प्रेडशीट में, क्षैतिज पंक्ति और ऊर्ध्वाधर कॉलम के प्रतिच्छेदन को 'सेल' कहा जाता है। प्रत्येक सेल को उसके कॉलम अक्षर और पंक्ति संख्या (उदा., A1, B5) वाले एक अद्वितीय संदर्भ पते द्वारा पहचाना जाता है। सेल Microsoft Excel में डेटा, टेक्स्ट या फ़ार्मुलों को संग्रहीत करने की मूल इकाई है।"}},
{type:"mcq",diff:"easy",en:{q:"How are rows labeled in an MS Excel worksheet?",opts:["With letters (A, B, C...)","With Roman numerals (I, II, III...)","With standard numbers (1, 2, 3...)","With special characters (@, #, $...)"],ans:2,exp:"In Microsoft Excel, the horizontal rows are labeled sequentially using standard numerical values starting from 1 and extending downwards. Conversely, the vertical columns are designated by alphabetical letters (A, B, C, ..., AA, AB, etc.). This distinct labeling system allows for precise cell referencing, such as 'C4', meaning column C and row 4."},hi:{q:"MS Excel वर्कशीट में पंक्तियों को कैसे लेबल किया जाता है?",opts:["अक्षरों के साथ (A, B, C...)","रोमन अंकों के साथ (I, II, III...)","मानक संख्याओं के साथ (1, 2, 3...)","विशेष वर्णों के साथ (@, #, $...)"],ans:2,exp:"Microsoft Excel में, क्षैतिज पंक्तियों को क्रमिक रूप से 1 से शुरू होकर नीचे की ओर मानक संख्यात्मक मानों का उपयोग करके लेबल किया जाता है। इसके विपरीत, ऊर्ध्वाधर कॉलम को वर्णमाला अक्षरों (A, B, C, ..., AA, AB, आदि) द्वारा नामित किया जाता है। यह विशिष्ट लेबलिंग सिस्टम सटीक सेल संदर्भ की अनुमति देता है, जैसे 'C4', जिसका अर्थ है कॉलम C और पंक्ति 4।"}},
{type:"mcq",diff:"easy",en:{q:"Which Excel feature automatically fills a series of data (like days of the week or numbers) in adjacent cells?",opts:["AutoFormat","AutoFill","AutoSum","AutoCorrect"],ans:1,exp:"AutoFill is a powerful feature in Excel that recognizes patterns in data, such as days of the week, months, or numerical sequences. By dragging the small square (fill handle) at the bottom-right corner of the active cell selection, users can quickly populate adjacent cells, significantly reducing manual data entry time."},hi:{q:"कौन सी Excel सुविधा स्वचालित रूप से आसन्न सेल में डेटा (जैसे सप्ताह के दिन या संख्या) की एक श्रृंखला भरती है?",opts:["AutoFormat","AutoFill","AutoSum","AutoCorrect"],ans:1,exp:"AutoFill Excel में एक शक्तिशाली विशेषता है जो डेटा में पैटर्न को पहचानती है, जैसे सप्ताह के दिन, महीने, या संख्यात्मक अनुक्रम। सक्रिय सेल चयन के निचले-दाएं कोने में छोटे वर्ग (फिल हैंडल) को खींचकर, उपयोगकर्ता आसन्न सेल को जल्दी से भर सकते हैं, जिससे मैन्युअल डेटा प्रविष्टि समय काफी कम हो जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Where is the active cell's address displayed in the Excel interface?",opts:["Title Bar","Status Bar","Name Box","Formula Bar"],ans:2,exp:"The Name Box is positioned to the left of the Formula Bar in the Excel interface. It continuously displays the cell reference or the defined name of the currently selected active cell. Users can also type a specific cell address or named range into the Name Box and press Enter to quickly navigate to that location."},hi:{q:"Excel इंटरफ़ेस में सक्रिय सेल का पता कहाँ प्रदर्शित होता है?",opts:["टाइटल बार","स्टेटस बार","नेम बॉक्स","फॉर्मूला बार"],ans:2,exp:"नेम बॉक्स Excel इंटरफ़ेस में फॉर्मूला बार के बाईं ओर स्थित होता है। यह लगातार सेल संदर्भ या वर्तमान में चयनित सक्रिय सेल का परिभाषित नाम प्रदर्शित करता है। उपयोगकर्ता नेम बॉक्स में एक विशिष्ट सेल पता या नामित श्रेणी भी टाइप कर सकते हैं और उस स्थान पर तुरंत नेविगेट करने के लिए Enter दबा सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What is the primary function of the Formula Bar in MS Excel?",opts:["To display only the final calculated result of a cell","To show the underlying formula or text content of the active cell","To create visual charts based on selected data","To format the color and font size of the text"],ans:1,exp:"The Formula Bar is located below the ribbon and shows the underlying formula, text, or exact value contained within the active cell. While the cell itself displays the computed result of a formula, the Formula Bar reveals the actual mathematical equation or function syntax used to generate that result, allowing for direct editing."},hi:{q:"MS Excel में फॉर्मूला बार का प्राथमिक कार्य क्या है?",opts:["केवल सेल का अंतिम गणना परिणाम प्रदर्शित करने के लिए","सक्रिय सेल का अंतर्निहित सूत्र या टेक्स्ट सामग्री दिखाने के लिए","चयनित डेटा के आधार पर दृश्य चार्ट बनाने के लिए","टेक्स्ट के रंग और फ़ॉन्ट आकार को स्वरूपित करने के लिए"],ans:1,exp:"फॉर्मूला बार रिबन के नीचे स्थित होता है और सक्रिय सेल के भीतर अंतर्निहित सूत्र, टेक्स्ट या सटीक मान दिखाता है। जबकि सेल स्वयं एक सूत्र का परिकलित परिणाम प्रदर्शित करता है, फॉर्मूला बार उस परिणाम को उत्पन्न करने के लिए उपयोग किए जाने वाले वास्तविक गणितीय समीकरण या फ़ंक्शन सिंटैक्स को प्रकट करता है, जिससे सीधे संपादन की अनुमति मिलती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which keyboard shortcut is universally used to save a workbook in MS Excel?",opts:["Ctrl + P","Ctrl + S","Ctrl + C","Ctrl + V"],ans:1,exp:"Pressing 'Ctrl + S' is the universal shortcut across Windows applications, including MS Excel, to save the current document. If the workbook is being saved for the first time, it prompts the 'Save As' dialog box, asking the user to specify the file name and destination path. For existing files, it updates the saved contents immediately."},hi:{q:"MS Excel में वर्कबुक को सहेजने के लिए सार्वभौमिक रूप से किस कीबोर्ड शॉर्टकट का उपयोग किया जाता है?",opts:["Ctrl + P","Ctrl + S","Ctrl + C","Ctrl + V"],ans:1,exp:"वर्तमान दस्तावेज़ को सहेजने के लिए 'Ctrl + S' दबाना MS Excel सहित Windows अनुप्रयोगों में सार्वभौमिक शॉर्टकट है। यदि वर्कबुक पहली बार सहेजी जा रही है, तो यह 'Save As' संवाद बॉक्स को संकेत देता है, उपयोगकर्ता को फ़ाइल नाम और गंतव्य पथ निर्दिष्ट करने के लिए कहता है। मौजूदा फ़ाइलों के लिए, यह सहेजी गई सामग्री को तुरंत अपडेट करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following functions adds all the numbers in a given range of cells?",opts:["COUNT()","MAX()","SUM()","AVERAGE()"],ans:2,exp:"The SUM() function is one of the most frequently used mathematical functions in Excel. It calculates the total addition of all numerical values within specified cells or ranges. For example, the formula '=SUM(A1:A10)' will add every number from cell A1 through A10, ignoring empty cells or text entries within that block."},hi:{q:"निम्नलिखित में से कौन सा फ़ंक्शन कोशिकाओं की दी गई सीमा में सभी संख्याओं को जोड़ता है?",opts:["COUNT()","MAX()","SUM()","AVERAGE()"],ans:2,exp:"SUM() फ़ंक्शन Excel में सबसे अधिक उपयोग किए जाने वाले गणितीय कार्यों में से एक है। यह निर्दिष्ट सेल या श्रेणी के भीतर सभी संख्यात्मक मानों के कुल जोड़ की गणना करता है। उदाहरण के लिए, सूत्र '=SUM(A1:A10)' सेल A1 से A10 तक के प्रत्येक नंबर को जोड़ देगा, उस ब्लॉक के भीतर खाली सेल या टेक्स्ट प्रविष्टियों को अनदेखा कर देगा।"}},
{type:"mcq",diff:"easy",en:{q:"Which function should you use to find the largest numerical value in a dataset?",opts:["LARGE()","MAX()","HIGH()","TOP()"],ans:1,exp:"The MAX() function evaluates a selected range of cells and returns the maximum (highest) numerical value present in that dataset. It is highly useful in statistical analysis, such as finding the highest sales figure in a financial report or the highest test score in a student grading sheet. The syntax is simply '=MAX(range)'."},hi:{q:"डेटासेट में सबसे बड़ा संख्यात्मक मान खोजने के लिए आपको किस फ़ंक्शन का उपयोग करना चाहिए?",opts:["LARGE()","MAX()","HIGH()","TOP()"],ans:1,exp:"MAX() फ़ंक्शन सेल की चयनित सीमा का मूल्यांकन करता है और उस डेटासेट में मौजूद अधिकतम (उच्चतम) संख्यात्मक मान देता है। सांख्यिकीय विश्लेषण में यह अत्यधिक उपयोगी है, जैसे वित्तीय रिपोर्ट में उच्चतम बिक्री का आंकड़ा या छात्र ग्रेडिंग शीट में उच्चतम परीक्षण स्कोर ढूंढना। सिंटैक्स बस '=MAX(range)' है।"}},
{type:"mcq",diff:"easy",en:{q:"What does the 'Merge & Center' command do in MS Excel?",opts:["It combines data from multiple sheets into one centralized table","It combines multiple adjacent cells into a single larger cell and centers the text","It merges two different Excel workbooks together","It calculates the average of a selected range of cells"],ans:1,exp:"The 'Merge & Center' feature is commonly used for creating titles and headings that span across multiple columns. It takes a contiguous selection of adjacent cells, physically merges them into one single, larger cell, and then aligns the text content to the center of this newly formed block. It only retains the data from the upper-leftmost cell."},hi:{q:"MS Excel में 'Merge & Center' कमांड क्या करता है?",opts:["यह कई शीट के डेटा को एक केंद्रीकृत तालिका में जोड़ता है","यह कई आसन्न सेल को एक बड़े सेल में जोड़ता है और टेक्स्ट को केंद्रित करता है","यह दो अलग-अलग Excel वर्कबुक को एक साथ मिलाता है","यह सेल की चयनित सीमा के औसत की गणना करता है"],ans:1,exp:"'Merge & Center' सुविधा का उपयोग आमतौर पर शीर्षक और हेडिंग बनाने के लिए किया जाता है जो कई कॉलम में फैले होते हैं। यह आसन्न सेल के निरंतर चयन को लेता है, उन्हें शारीरिक रूप से एक एकल, बड़े सेल में मिलाता है, और फिर इस नवगठित ब्लॉक के केंद्र में टेक्स्ट सामग्री को संरेखित करता है। यह केवल सबसे ऊपरी बाएँ सेल का डेटा बरकरार रखता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which keyboard shortcut is used to select the entire worksheet in MS Excel?",opts:["Ctrl + A","Ctrl + E","Ctrl + W","Ctrl + X"],ans:0,exp:"The shortcut 'Ctrl + A' executes the 'Select All' command. When pressed inside an active data region, it selects the contiguous data range. If pressed a second time, or if pressed when an empty cell is active, it selects every single cell in the entire active worksheet. It is essential for global formatting or copying."},hi:{q:"MS Excel में संपूर्ण वर्कशीट का चयन करने के लिए किस कीबोर्ड शॉर्टकट का उपयोग किया जाता है?",opts:["Ctrl + A","Ctrl + E","Ctrl + W","Ctrl + X"],ans:0,exp:"शॉर्टकट 'Ctrl + A' 'Select All' कमांड निष्पादित करता है। जब किसी सक्रिय डेटा क्षेत्र के अंदर दबाया जाता है, तो यह सन्निहित डेटा सीमा का चयन करता है। यदि इसे दूसरी बार दबाया जाता है, या यदि खाली सेल सक्रिय होने पर दबाया जाता है, तो यह संपूर्ण सक्रिय वर्कशीट में हर एक सेल का चयन करता है। यह वैश्विक स्वरूपण या प्रतिलिपि बनाने के लिए आवश्यक है।"}},
{type:"mcq",diff:"easy",en:{q:"What is a contiguous block of selected cells in Excel called?",opts:["A Parameter","A Function","A Range","A Matrix"],ans:2,exp:"A group of contiguous or connected cells in a worksheet is formally termed a 'Range'. A cell range is defined by the reference of its upper-left cell and lower-right cell, separated by a colon. For example, 'A1:C6' indicates a block encompassing all cells from column A to C and rows 1 through 6. Ranges are vital for applying formulas to multiple cells."},hi:{q:"Excel में चयनित कोशिकाओं के एक सन्निहित ब्लॉक को क्या कहा जाता है?",opts:["एक पैरामीटर","एक फंक्शन","एक रेंज","एक मैट्रिक्स"],ans:2,exp:"वर्कशीट में सन्निहित या जुड़ी हुई कोशिकाओं के समूह को औपचारिक रूप से 'रेंज' कहा जाता है। एक सेल रेंज को उसके ऊपरी-बाएँ सेल और निचले-दाएँ सेल के संदर्भ द्वारा परिभाषित किया जाता है, जिसे कोलन द्वारा अलग किया जाता है। उदाहरण के लिए, 'A1:C6' एक ब्लॉक को इंगित करता है जिसमें कॉलम A से C और पंक्तियों 1 से 6 तक के सभी सेल शामिल हैं। कई कोशिकाओं पर सूत्र लागू करने के लिए रेंज महत्वपूर्ण हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which function would you use to calculate the arithmetic mean of a set of numbers?",opts:["MEAN()","MEDIAN()","AVERAGE()","SUM()"],ans:2,exp:"The AVERAGE() function calculates the arithmetic mean of a list of supplied numbers. It does this internally by summing all the numerical values in the designated range and then dividing that total by the count of numeric entries. Empty cells and cells containing text are automatically ignored during this calculation process."},hi:{q:"संख्याओं के एक सेट के अंकगणितीय माध्य की गणना करने के लिए आप किस फ़ंक्शन का उपयोग करेंगे?",opts:["MEAN()","MEDIAN()","AVERAGE()","SUM()"],ans:2,exp:"AVERAGE() फ़ंक्शन आपूर्ति की गई संख्याओं की सूची के अंकगणितीय माध्य की गणना करता है। यह निर्दिष्ट सीमा में सभी संख्यात्मक मानों को जोड़कर और फिर उस कुल को संख्यात्मक प्रविष्टियों की गिनती से विभाजित करके आंतरिक रूप से ऐसा करता है। इस गणना प्रक्रिया के दौरान खाली सेल और टेक्स्ट वाले सेल को स्वचालित रूप से अनदेखा कर दिया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does the 'Wrap Text' feature do in a cell?",opts:["It surrounds the cell with a thick border","It forces long text to fit on multiple lines within the same cell","It rotates the text by 90 degrees","It deletes extra characters that do not fit in the cell width"],ans:1,exp:"The 'Wrap Text' formatting feature adjusts how content is displayed inside a cell. Instead of overflowing into adjacent empty cells or being visually cut off by adjacent filled cells, Wrap Text automatically increases the row height and breaks the long string of text into multiple lines within the original cell boundaries."},hi:{q:"एक सेल में 'Wrap Text' सुविधा क्या करती है?",opts:["यह सेल को एक मोटी सीमा से घेरता है","यह लंबे टेक्स्ट को एक ही सेल के भीतर कई पंक्तियों में फिट होने के लिए बाध्य करता है","यह टेक्स्ट को 90 डिग्री से घुमाता है","यह अतिरिक्त वर्णों को हटा देता है जो सेल की चौड़ाई में फिट नहीं होते हैं"],ans:1,exp:"'Wrap Text' स्वरूपण सुविधा यह समायोजित करती है कि सेल के अंदर सामग्री कैसे प्रदर्शित होती है। आसन्न खाली सेल में अतिप्रवाह होने या आसन्न भरे हुए सेल द्वारा दृष्टिगत रूप से काटे जाने के बजाय, Wrap Text स्वचालित रूप से पंक्ति की ऊंचाई बढ़ाता है और लंबे टेक्स्ट को मूल सेल सीमाओं के भीतर कई पंक्तियों में तोड़ देता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which key combination allows you to quickly print the active worksheet?",opts:["Ctrl + P","Alt + P","Shift + P","Windows + P"],ans:0,exp:"Pressing 'Ctrl + P' instantly brings up the Print dialog box or the Print Preview screen in the Backstage view (in modern Excel versions). This interface allows the user to review the layout, select a printer, adjust margins, set the specific print area, and define the number of copies before finalizing the print job."},hi:{q:"कौन सा कुंजी संयोजन आपको सक्रिय वर्कशीट को जल्दी से प्रिंट करने की अनुमति देता है?",opts:["Ctrl + P","Alt + P","Shift + P","Windows + P"],ans:0,exp:"'Ctrl + P' दबाने पर बैकस्टेज दृश्य (आधुनिक Excel संस्करणों में) में प्रिंट संवाद बॉक्स या प्रिंट पूर्वावलोकन स्क्रीन तुरंत आ जाती है। यह इंटरफ़ेस उपयोगकर्ता को लेआउट की समीक्षा करने, एक प्रिंटर का चयन करने, मार्जिन समायोजित करने, विशिष्ट प्रिंट क्षेत्र सेट करने और प्रिंट कार्य को अंतिम रूप देने से पहले प्रतियों की संख्या को परिभाषित करने की अनुमति देता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which page orientation options are available in MS Excel for printing?",opts:["Vertical and Horizontal","Portrait and Landscape","Top and Bottom","Straight and Slanted"],ans:1,exp:"In the Page Setup options, Excel provides two fundamental page orientations: Portrait and Landscape. Portrait orientation prints the page vertically (taller than it is wide), which is standard for most documents. Landscape orientation prints the page horizontally (wider than it is tall), which is extremely useful for wide spreadsheets with many columns."},hi:{q:"प्रिंटिंग के लिए MS Excel में कौन से पेज ओरिएंटेशन विकल्प उपलब्ध हैं?",opts:["लंबवत और क्षैतिज (Vertical and Horizontal)","पोर्ट्रेट और लैंडस्केप (Portrait and Landscape)","ऊपर और नीचे (Top and Bottom)","सीधा और तिरछा (Straight and Slanted)"],ans:1,exp:"पेज सेटअप विकल्पों में, Excel दो मूलभूत पेज ओरिएंटेशन प्रदान करता है: पोर्ट्रेट और लैंडस्केप। पोर्ट्रेट ओरिएंटेशन पृष्ठ को लंबवत रूप से प्रिंट करता है (चौड़ाई से अधिक लंबा), जो अधिकांश दस्तावेज़ों के लिए मानक है। लैंडस्केप ओरिएंटेशन पृष्ठ को क्षैतिज रूप से प्रिंट करता है (लंबाई से अधिक चौड़ा), जो कई कॉलम वाले चौड़े स्प्रेडशीट के लिए बेहद उपयोगी है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following functions will count the total number of cells in a range that contain only numerical data?",opts:["COUNT()","COUNTA()","COUNTBLANK()","COUNTIF()"],ans:0,exp:"The COUNT() function is specifically designed to count only the cells within a designated range that contain numerical values, dates, or times. It explicitly ignores cells that are blank, contain text strings, or hold logical values like TRUE/FALSE. For counting all non-empty cells regardless of data type, COUNTA() is used instead."},hi:{q:"निम्नलिखित में से कौन सा फ़ंक्शन एक श्रेणी में केवल संख्यात्मक डेटा वाले सेल की कुल संख्या की गणना करेगा?",opts:["COUNT()","COUNTA()","COUNTBLANK()","COUNTIF()"],ans:0,exp:"COUNT() फ़ंक्शन विशेष रूप से एक निर्दिष्ट सीमा के भीतर केवल उन सेल की गणना करने के लिए डिज़ाइन किया गया है जिनमें संख्यात्मक मान, दिनांक या समय होते हैं। यह स्पष्ट रूप से उन सेल को अनदेखा करता है जो खाली हैं, जिनमें टेक्स्ट स्ट्रिंग हैं, या जो TRUE/FALSE जैसे तार्किक मान रखते हैं। डेटा प्रकार की परवाह किए बिना सभी गैर-खाली सेल की गणना करने के लिए, इसके बजाय COUNTA() का उपयोग किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which Excel function returns the current system date but NOT the time?",opts:["NOW()","DATE()","TODAY()","CURRENT()"],ans:2,exp:"The TODAY() function continuously fetches the current date based on the system's internal clock and displays it in the cell. It takes no arguments, structured simply as '=TODAY()'. It differs from the NOW() function because TODAY() only outputs the date, whereas NOW() outputs both the current date and the exact current time."},hi:{q:"कौन सा Excel फ़ंक्शन वर्तमान सिस्टम दिनांक देता है लेकिन समय नहीं?",opts:["NOW()","DATE()","TODAY()","CURRENT()"],ans:2,exp:"TODAY() फ़ंक्शन सिस्टम की आंतरिक घड़ी के आधार पर वर्तमान दिनांक को लगातार प्राप्त करता है और इसे सेल में प्रदर्शित करता है। यह कोई तर्क नहीं लेता है, इसे केवल '=TODAY()' के रूप में संरचित किया जाता है। यह NOW() फ़ंक्शन से भिन्न है क्योंकि TODAY() केवल दिनांक आउटपुट करता है, जबकि NOW() वर्तमान दिनांक और सटीक वर्तमान समय दोनों आउटपुट करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which character is used to create an absolute cell reference in MS Excel formulas?",opts:["& (Ampersand)","$ (Dollar sign)","# (Hash)","@ (At symbol)"],ans:1,exp:"The dollar sign ($) is critical in Excel for absolute referencing. When placed before the column letter and row number (e.g., $A$1), it locks that specific cell reference. Consequently, when the formula is copied or dragged using AutoFill to other cells, the reference to $A$1 remains constant and does not shift relative to the new position."},hi:{q:"MS Excel फ़ार्मुलों में निरपेक्ष (absolute) सेल संदर्भ बनाने के लिए किस वर्ण का उपयोग किया जाता है?",opts:["& (एम्परसेंड)","$ (डॉलर चिह्न)","# (हैश)","@ (एट प्रतीक)"],ans:1,exp:"पूर्ण (absolute) संदर्भ के लिए Excel में डॉलर चिह्न ($) महत्वपूर्ण है। जब इसे कॉलम अक्षर और पंक्ति संख्या (जैसे, $A$1) से पहले रखा जाता है, तो यह उस विशिष्ट सेल संदर्भ को लॉक कर देता है। नतीजतन, जब सूत्र की प्रतिलिपि बनाई जाती है या अन्य सेल में AutoFill का उपयोग करके खींचा जाता है, तो $A$1 का संदर्भ स्थिर रहता है और नई स्थिति के सापेक्ष नहीं बदलता है।"}},
{type:"mcq",diff:"easy",en:{q:"What happens when you press the shortcut 'Ctrl + C' on a selected cell?",opts:["It clears the formatting of the cell","It cuts the cell contents to paste elsewhere","It copies the cell's contents and formatting to the clipboard","It centers the text inside the cell"],ans:2,exp:"'Ctrl + C' is the standard shortcut to invoke the Copy command. It places a duplicate of the active cell's contents—including its underlying formula, resulting value, and any applied formatting—into the system clipboard. The original cell remains unchanged, but a dotted 'marching ants' border appears around it indicating it is ready to be pasted."},hi:{q:"जब आप किसी चयनित सेल पर शॉर्टकट 'Ctrl + C' दबाते हैं तो क्या होता है?",opts:["यह सेल के स्वरूपण को साफ़ करता है","यह कहीं और पेस्ट करने के लिए सेल सामग्री को कट करता है","यह सेल की सामग्री और स्वरूपण को क्लिपबोर्ड पर कॉपी करता है","यह सेल के अंदर टेक्स्ट को केंद्रित करता है"],ans:2,exp:"'Ctrl + C' कॉपी कमांड को लागू करने के लिए मानक शॉर्टकट है। यह सक्रिय सेल की सामग्री का डुप्लिकेट—जिसमें इसके अंतर्निहित सूत्र, परिणामी मान और कोई लागू स्वरूपण शामिल है—सिस्टम क्लिपबोर्ड में रखता है। मूल सेल अपरिवर्तित रहता है, लेकिन इसके चारों ओर एक बिंदीदार 'मार्चिंग चींटियों' की सीमा दिखाई देती है जो यह दर्शाती है कि यह पेस्ट होने के लिए तैयार है।"}},
{type:"mcq",diff:"easy",en:{q:"What happens to a relative cell reference when a formula is copied down to the next row?",opts:["It becomes an absolute reference","It causes a #REF! error","It stays exactly the same","The row number automatically increases by one"],ans:3,exp:"A relative reference (like A1) is designed to change based on its relative displacement when copied. If you copy a formula referencing A1 down by one row, the reference automatically updates to A2. This dynamic behavior is what makes Excel so powerful, allowing users to apply a single calculation logic to an entire dataset effortlessly."},hi:{q:"जब किसी सूत्र को अगली पंक्ति में कॉपी किया जाता है तो सापेक्ष (relative) सेल संदर्भ का क्या होता है?",opts:["यह एक निरपेक्ष (absolute) संदर्भ बन जाता है","यह #REF! त्रुटि का कारण बनता है","यह बिल्कुल वैसा ही रहता है","पंक्ति संख्या स्वचालित रूप से एक बढ़ जाती है"],ans:3,exp:"एक सापेक्ष संदर्भ (जैसे A1) को कॉपी किए जाने पर उसके सापेक्ष विस्थापन के आधार पर बदलने के लिए डिज़ाइन किया गया है। यदि आप एक पंक्ति नीचे A1 का संदर्भ देने वाले सूत्र की प्रतिलिपि बनाते हैं, तो संदर्भ स्वचालित रूप से A2 में अपडेट हो जाता है। यह गतिशील व्यवहार वह है जो Excel को इतना शक्तिशाली बनाता है, जिससे उपयोगकर्ता आसानी से संपूर्ण डेटासेट पर एकल गणना तर्क लागू कर सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"In Excel, how can you delete the contents of a cell without deleting the cell itself or its formatting?",opts:["Select the cell and press Backspace","Select the cell and press the Delete key","Right-click and choose Delete","Use the Format Painter tool"],ans:1,exp:"Pressing the 'Delete' key on the keyboard clears the data, text, or formulas stored inside the selected cell. Crucially, it leaves the cell structure intact and preserves any background colors, borders, or number formats applied to that cell. Right-clicking and choosing 'Delete' actually removes the physical cell, shifting adjacent cells to fill the gap."},hi:{q:"Excel में, आप सेल या उसके स्वरूपण को हटाए बिना सेल की सामग्री को कैसे हटा सकते हैं?",opts:["सेल का चयन करें और Backspace दबाएं","सेल का चयन करें और Delete कुंजी दबाएं","राइट-क्लिक करें और Delete चुनें","Format Painter टूल का उपयोग करें"],ans:1,exp:"कीबोर्ड पर 'Delete' कुंजी दबाने से चयनित सेल के अंदर संग्रहीत डेटा, टेक्स्ट या फ़ार्मुलों को साफ़ किया जाता है। महत्वपूर्ण रूप से, यह सेल संरचना को अक्षुण्ण छोड़ देता है और उस सेल पर लागू किसी भी पृष्ठभूमि रंग, बॉर्डर या संख्या स्वरूपों को सुरक्षित रखता है। राइट-क्लिक करके और 'Delete' चुनने से वास्तव में भौतिक सेल हट जाती है, जिससे आसन्न सेल गैप को भरने के लिए खिसक जाती हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which symbol indicates that a column is not wide enough to display the numerical value it contains?",opts:["#REF!","####","#NAME?","#DIV/0!"],ans:1,exp:"When a cell is populated with a numerical value, date, or time that physically exceeds the established pixel width of the column, Excel displays a sequence of hash symbols (####). This is not an error in calculation. To fix this visual issue, the user simply needs to widen the column by dragging the column header boundary."},hi:{q:"कौन सा प्रतीक इंगित करता है कि एक कॉलम इसमें मौजूद संख्यात्मक मान प्रदर्शित करने के लिए पर्याप्त चौड़ा नहीं है?",opts:["#REF!","####","#NAME?","#DIV/0!"],ans:1,exp:"जब किसी सेल में संख्यात्मक मान, दिनांक या समय भरा जाता है जो भौतिक रूप से कॉलम की स्थापित पिक्सेल चौड़ाई से अधिक होता है, तो Excel हैश प्रतीकों (####) का एक क्रम प्रदर्शित करता है। यह गणना में कोई त्रुटि नहीं है। इस दृश्य समस्या को ठीक करने के लिए, उपयोगकर्ता को केवल कॉलम हेडर सीमा को खींचकर कॉलम को चौड़ा करने की आवश्यकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which action is performed by the shortcut 'Ctrl + V'?",opts:["Validating data","Pasting the contents from the clipboard","Viewing print preview","Inserting a new variable"],ans:1,exp:"The 'Ctrl + V' shortcut performs the Paste command. It outputs whatever data is currently stored in the operating system's clipboard into the active cell or range. This relies on a preceding action of Copy (Ctrl+C) or Cut (Ctrl+X). Users can also utilize 'Paste Special' to paste only specific attributes like values or formatting."},hi:{q:"शॉर्टकट 'Ctrl + V' द्वारा कौन सी क्रिया की जाती है?",opts:["डेटा को मान्य करना (Validating data)","क्लिपबोर्ड से सामग्री पेस्ट करना","प्रिंट पूर्वावलोकन देखना","एक नया चर (variable) सम्मिलित करना"],ans:1,exp:"'Ctrl + V' शॉर्टकट पेस्ट कमांड निष्पादित करता है। यह वर्तमान में ऑपरेटिंग सिस्टम के क्लिपबोर्ड में संग्रहीत डेटा को सक्रिय सेल या रेंज में आउटपुट करता है। यह कॉपी (Ctrl+C) या कट (Ctrl+X) की पूर्ववर्ती कार्रवाई पर निर्भर करता है। उपयोगकर्ता केवल विशिष्ट विशेषताओं जैसे मान या स्वरूपण को पेस्ट करने के लिए 'पेस्ट स्पेशल' का भी उपयोग कर सकते हैं।"}},
{type:"tf",diff:"easy",en:{q:"The Formula Bar in MS Excel always displays the underlying formula or text of the currently active cell.",opts:["True","False"],ans:0,exp:"True. The primary purpose of the Formula Bar is to provide a dedicated space to view and edit the raw data or mathematical formulas behind the active cell, regardless of what final computed result is displayed in the grid."},hi:{q:"MS Excel में फॉर्मूला बार हमेशा वर्तमान में सक्रिय सेल का अंतर्निहित सूत्र या टेक्स्ट प्रदर्शित करता है।",opts:["सही","गलत"],ans:0,exp:"सही। फॉर्मूला बार का प्राथमिक उद्देश्य सक्रिय सेल के पीछे कच्चे डेटा या गणितीय फ़ार्मुलों को देखने और संपादित करने के लिए एक समर्पित स्थान प्रदान करना है, भले ही ग्रिड में अंतिम परिकलित परिणाम क्या प्रदर्शित किया गया हो।"}},
{type:"tf",diff:"easy",en:{q:"It is impossible to rename a worksheet tab once it has been created in a workbook.",opts:["True","False"],ans:1,exp:"False. Worksheet tabs are highly customizable. Users can easily rename them to reflect the data they contain by either double-clicking the tab name (like 'Sheet1') and typing a new name, or by right-clicking the tab and selecting 'Rename' from the context menu."},hi:{q:"वर्कबुक में एक बार बनाए जाने के बाद वर्कशीट टैब का नाम बदलना असंभव है।",opts:["सही","गलत"],ans:1,exp:"गलत। वर्कशीट टैब अत्यधिक अनुकूलन योग्य हैं। उपयोगकर्ता टैब नाम (जैसे 'Sheet1') पर डबल-क्लिक करके और नया नाम टाइप करके, या टैब पर राइट-क्लिक करके और संदर्भ मेनू से 'Rename' का चयन करके आसानी से उनका नाम बदल सकते हैं जो डेटा वे रखते हैं उसे प्रतिबिंबित करने के लिए।"}},
{type:"mcq",diff:"medium",en:{q:"What is the key difference between the COUNT() and COUNTA() functions in Excel?",opts:["COUNT only adds numbers; COUNTA adds text","COUNT counts only numeric cells; COUNTA counts all non-empty cells","COUNT counts words; COUNTA counts numbers","There is no difference, they are identical functions"],ans:1,exp:"While COUNT() is restricted to tallying only those cells that contain numerical data (including dates and times), the COUNTA() function evaluates the presence of any data type. COUNTA() will count numbers, text, boolean values, and even errors, effectively tallying every non-blank cell in the specified range."},hi:{q:"Excel में COUNT() और COUNTA() फ़ंक्शन के बीच मुख्य अंतर क्या है?",opts:["COUNT केवल संख्याएँ जोड़ता है; COUNTA टेक्स्ट जोड़ता है","COUNT केवल संख्यात्मक सेल की गणना करता है; COUNTA सभी गैर-खाली सेल की गणना करता है","COUNT शब्दों की गणना करता है; COUNTA संख्याओं की गणना करता है","कोई अंतर नहीं है, वे समान कार्य हैं"],ans:1,exp:"जबकि COUNT() केवल उन सेल को गिनने तक सीमित है जिनमें संख्यात्मक डेटा (दिनांक और समय सहित) होता है, COUNTA() फ़ंक्शन किसी भी डेटा प्रकार की उपस्थिति का मूल्यांकन करता है। COUNTA() संख्याओं, पाठ, बूलियन मानों और यहां तक कि त्रुटियों की भी गणना करेगा, प्रभावी रूप से निर्दिष्ट सीमा में प्रत्येक गैर-रिक्त सेल की गणना करेगा।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following is the correct syntax for the IF() function?",opts:["=IF(true_value, false_value, condition)","=IF(condition, value_if_true, value_if_false)","=IF(value_if_true, condition, value_if_false)","=IF(value_if_false, value_if_true, condition)"],ans:1,exp:"The IF() logical function requires three arguments: a logical test (condition) that evaluates to TRUE or FALSE, the output returned if the test is TRUE, and the output returned if the test is FALSE. The correct structured syntax is: =IF(logical_test, [value_if_true], [value_if_false])."},hi:{q:"निम्नलिखित में से कौन सा IF() फ़ंक्शन के लिए सही सिंटैक्स है?",opts:["=IF(true_value, false_value, condition)","=IF(condition, value_if_true, value_if_false)","=IF(value_if_true, condition, value_if_false)","=IF(value_if_false, value_if_true, condition)"],ans:1,exp:"IF() तार्किक फ़ंक्शन के लिए तीन तर्कों की आवश्यकता होती है: एक तार्किक परीक्षण (शर्त) जो TRUE या FALSE का मूल्यांकन करता है, परीक्षण TRUE होने पर आउटपुट दिया जाता है, और यदि परीक्षण FALSE है तो आउटपुट वापस आ जाता है। सही संरचित सिंटैक्स है: =IF(logical_test, [value_if_true], [value_if_false])।"}},
{type:"mcq",diff:"medium",en:{q:"What operation does the CONCATENATE() function (or CONCAT) perform?",opts:["Calculates the mathematical product of multiple cells","Joins two or more text strings together into a single string","Removes spaces from text","Extracts the first letter of a word"],ans:1,exp:"The CONCATENATE() function (updated to CONCAT in newer Excel versions) is a text manipulation tool. It seamlessly joins two or more separate text strings, numbers, or cell references into one continuous text string. For instance, combining a First Name in A1 and Last Name in B1 into a Full Name in C1."},hi:{q:"CONCATENATE() फ़ंक्शन (या CONCAT) कौन सा ऑपरेशन करता है?",opts:["कई कोशिकाओं के गणितीय उत्पाद की गणना करता है","दो या दो से अधिक टेक्स्ट स्ट्रिंग्स को एक स्ट्रिंग में जोड़ता है","टेक्स्ट से रिक्त स्थान हटाता है","किसी शब्द का पहला अक्षर निकालता है"],ans:1,exp:"CONCATENATE() फ़ंक्शन (नए Excel संस्करणों में CONCAT में अपडेट किया गया) एक टेक्स्ट हेरफेर टूल है। यह मूल रूप से दो या दो से अधिक अलग-अलग टेक्स्ट स्ट्रिंग्स, संख्याओं या सेल संदर्भों को एक निरंतर टेक्स्ट स्ट्रिंग में जोड़ता है। उदाहरण के लिए, A1 में प्रथम नाम और B1 में अंतिम नाम को C1 में पूर्ण नाम में जोड़ना।"}},
{type:"mcq",diff:"medium",en:{q:"If cell A1 contains the text 'COMPUTER', what will the formula '=LEFT(A1, 4)' return?",opts:["COMP","UTER","MPUT","PUTE"],ans:0,exp:"The LEFT() function extracts a specified number of characters from the absolute beginning (leftmost side) of a text string. The syntax is =LEFT(text, [num_chars]). In this scenario, extracting 4 characters from the left of the string 'COMPUTER' yields the substring 'COMP'."},hi:{q:"यदि सेल A1 में टेक्स्ट 'COMPUTER' है, तो सूत्र '=LEFT(A1, 4)' क्या लौटाएगा?",opts:["COMP","UTER","MPUT","PUTE"],ans:0,exp:"LEFT() फ़ंक्शन टेक्स्ट स्ट्रिंग के पूर्ण प्रारंभ (सबसे बाईं ओर) से निर्दिष्ट संख्या में वर्ण निकालता है। सिंटैक्स =LEFT(text, [num_chars]) है। इस परिदृश्य में, 'COMPUTER' स्ट्रिंग के बाईं ओर से 4 वर्ण निकालने पर सबस्ट्रिंग 'COMP' प्राप्त होता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which function is used to convert all letters in a text string to uppercase?",opts:["CAPITAL()","BIG()","UPPER()","MAX()"],ans:2,exp:"The UPPER() function is a text formatting function that takes a supplied text string and strictly converts every lowercase alphabetical character within it into its uppercase equivalent. It has no effect on numbers, punctuation marks, or letters that are already uppercase."},hi:{q:"टेक्स्ट स्ट्रिंग के सभी अक्षरों को अपरकेस (बड़े अक्षरों) में बदलने के लिए किस फ़ंक्शन का उपयोग किया जाता है?",opts:["CAPITAL()","BIG()","UPPER()","MAX()"],ans:2,exp:"UPPER() फ़ंक्शन एक टेक्स्ट स्वरूपण फ़ंक्शन है जो एक आपूर्ति की गई टेक्स्ट स्ट्रिंग लेता है और उसके भीतर के प्रत्येक छोटे वर्णमाला वर्ण को उसके अपरकेस समकक्ष में सख्ती से परिवर्तित करता है। इसका उन संख्याओं, विराम चिह्नों या अक्षरों पर कोई प्रभाव नहीं पड़ता है जो पहले से ही अपरकेस हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What is the specific purpose of the TRIM() function in MS Excel?",opts:["To cut decimal places from numbers","To remove all spaces from text except for single spaces between words","To delete the entire contents of a cell","To shorten a text string to 10 characters"],ans:1,exp:"Data imported from external systems often contains irregular spacing. The TRIM() function cleans this data by aggressively removing all leading spaces, all trailing spaces, and any multiple consecutive spaces between words, strictly leaving only a single space between individual words."},hi:{q:"MS Excel में TRIM() फ़ंक्शन का विशिष्ट उद्देश्य क्या है?",opts:["संख्याओं से दशमलव स्थानों को काटना","शब्दों के बीच एकल रिक्त स्थान को छोड़कर टेक्स्ट से सभी रिक्त स्थान को हटाना","एक सेल की संपूर्ण सामग्री को हटाना","एक टेक्स्ट स्ट्रिंग को 10 वर्णों तक छोटा करना"],ans:1,exp:"बाहरी सिस्टम से आयात किए गए डेटा में अक्सर अनियमित रिक्ति होती है। TRIM() फ़ंक्शन इस डेटा को सभी अग्रणी रिक्त स्थान (leading spaces), सभी अनुगामी रिक्त स्थान (trailing spaces) और शब्दों के बीच किसी भी एकाधिक लगातार रिक्त स्थान को हटाकर साफ करता है, और व्यक्तिगत शब्दों के बीच केवल एक ही स्थान छोड़ता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is a Pivot Table primarily designed to do?",opts:["To create basic geometric shapes","To summarize, analyze, and extract insights from large datasets dynamically","To automatically translate text into another language","To protect the workbook with strong encryption"],ans:1,exp:"A Pivot Table is one of Excel's most powerful analytical tools. It allows users to quickly aggregate, summarize, and cross-tabulate massive amounts of raw data without writing complicated formulas. By simply dragging and dropping fields, users can calculate sums, averages, and counts, shifting columns to rows ('pivoting') to reveal data trends."},hi:{q:"पिवट टेबल मुख्य रूप से क्या करने के लिए डिज़ाइन किया गया है?",opts:["बुनियादी ज्यामितीय आकृतियाँ बनाने के लिए","बड़े डेटासेट को गतिशील रूप से सारांशित, विश्लेषण और अंतर्दृष्टि निकालने के लिए","पाठ का स्वचालित रूप से किसी अन्य भाषा में अनुवाद करने के लिए","मजबूत एन्क्रिप्शन के साथ वर्कबुक की सुरक्षा के लिए"],ans:1,exp:"पिवट टेबल Excel के सबसे शक्तिशाली विश्लेषणात्मक उपकरणों में से एक है। यह उपयोगकर्ताओं को जटिल फ़ार्मुलों को लिखे बिना बड़ी मात्रा में कच्चे डेटा को तुरंत एकत्र करने, सारांशित करने और क्रॉस-सारणीबद्ध करने की अनुमति देता है। केवल फ़ील्ड को खींचकर और छोड़कर, उपयोगकर्ता डेटा प्रवृत्तियों को प्रकट करने के लिए पंक्तियों ('पिवटिंग') में कॉलम को स्थानांतरित करके योग, औसत और गणना की गणना कर सकते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"How does a 'Mixed Cell Reference' behave differently from an absolute reference?",opts:["It causes an error if dragged diagonally","It locks only the row OR the column, but not both","It connects two different workbooks together","It mixes text and numbers together"],ans:1,exp:"A mixed reference integrates both relative and absolute referencing mechanisms. By placing a dollar sign in front of only one component—either the column letter (e.g., $A1) or the row number (e.g., A$1)—Excel holds that specific coordinate constant during copy-pasting, while allowing the un-locked coordinate to shift dynamically."},hi:{q:"एक 'मिश्रित सेल संदर्भ (Mixed Cell Reference)' एक निरपेक्ष संदर्भ से अलग कैसे व्यवहार करता है?",opts:["यदि इसे तिरछे खींचा जाए तो यह त्रुटि का कारण बनता है","यह केवल पंक्ति या कॉलम को लॉक करता है, लेकिन दोनों को नहीं","यह दो अलग-अलग वर्कबुक को एक साथ जोड़ता है","यह पाठ और संख्याओं को एक साथ मिलाता है"],ans:1,exp:"एक मिश्रित संदर्भ (mixed reference) सापेक्ष और पूर्ण दोनों संदर्भ तंत्रों को एकीकृत करता है। केवल एक घटक के सामने डॉलर का चिह्न लगाकर—या तो कॉलम अक्षर (उदा., $A1) या पंक्ति संख्या (उदा., A$1)—कॉपी-पेस्टिंग के दौरान Excel उस विशिष्ट समन्वय को स्थिर रखता है, जबकि अन-लॉक समन्वय को गतिशील रूप से स्थानांतरित करने की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which keyboard key allows you to quickly cycle through relative, absolute, and mixed cell references while editing a formula?",opts:["F2","F4","F5","F9"],ans:1,exp:"When typing or editing a cell reference in the Formula Bar, pressing the F4 function key rapidly cycles the reference through its four possible states: relative (A1), absolute ($A$1), mixed row-locked (A$1), and mixed column-locked ($A1). This shortcut saves immense time over manually typing dollar signs."},hi:{q:"एक सूत्र संपादित करते समय कौन सी कीबोर्ड कुंजी आपको सापेक्ष, पूर्ण और मिश्रित सेल संदर्भों के माध्यम से जल्दी से साइकिल चलाने की अनुमति देती है?",opts:["F2","F4","F5","F9"],ans:1,exp:"फॉर्मूला बार में सेल संदर्भ टाइप या संपादित करते समय, F4 फ़ंक्शन कुंजी को दबाने से संदर्भ अपनी चार संभावित स्थितियों के माध्यम से तेजी से घूमता है: सापेक्ष (A1), पूर्ण ($A$1), मिश्रित पंक्ति-लॉक (A$1), और मिश्रित कॉलम-लॉक ($A1)। यह शॉर्टकट मैन्युअल रूप से डॉलर चिह्न टाइप करने की तुलना में काफी समय बचाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What error message does MS Excel return if you attempt to divide a number by a cell containing zero or no value?",opts:["#VALUE!","#N/A","#DIV/0!","#NUM!"],ans:2,exp:"The '#DIV/0!' error explicitly indicates a mathematical impossibility: division by zero. This occurs when a formula explicitly divides by 0, or more commonly, when it divides by a reference cell that is either completely blank or holds the number zero. Using functions like IFERROR() can help suppress and manage this error."},hi:{q:"यदि आप किसी संख्या को शून्य या बिना किसी मान वाले सेल से विभाजित करने का प्रयास करते हैं तो MS Excel कौन सा त्रुटि संदेश देता है?",opts:["#VALUE!","#N/A","#DIV/0!","#NUM!"],ans:2,exp:"'#DIV/0!' त्रुटि स्पष्ट रूप से एक गणितीय असंभवता को इंगित करती है: शून्य से विभाजन। यह तब होता है जब एक सूत्र स्पष्ट रूप से 0 से विभाजित होता है, या अधिक सामान्यतः, जब यह एक संदर्भ सेल द्वारा विभाजित होता है जो या तो पूरी तरह से खाली होता है या संख्या शून्य रखता है। IFERROR() जैसे कार्यों का उपयोग करने से इस त्रुटि को दबाने और प्रबंधित करने में मदद मिल सकती है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the 'Set Print Area' command achieve in page layout?",opts:["It automatically prints the entire workbook","It forces the printer to use color ink","It defines a specific, limited range of cells to be printed, ignoring the rest of the worksheet","It prints the gridlines and row numbers"],ans:2,exp:"By selecting 'Set Print Area' from the Page Layout tab, the user dictates exactly which block of data should be sent to the printer. Any data residing outside this defined boundary on the worksheet is entirely ignored during the print job. This is vital for printing summary tables without printing vast arrays of raw source data."},hi:{q:"पेज लेआउट में 'Set Print Area' कमांड क्या हासिल करता है?",opts:["यह स्वचालित रूप से पूरी वर्कबुक को प्रिंट करता है","यह प्रिंटर को रंगीन स्याही का उपयोग करने के लिए मजबूर करता है","यह शेष वर्कशीट को अनदेखा करते हुए, मुद्रित किए जाने वाले सेल की एक विशिष्ट, सीमित सीमा को परिभाषित करता है","यह ग्रिडलाइन और पंक्ति संख्याओं को प्रिंट करता है"],ans:2,exp:"पेज लेआउट टैब से 'Set Print Area' का चयन करके, उपयोगकर्ता यह निर्धारित करता है कि डेटा के किस ब्लॉक को प्रिंटर पर भेजा जाना चाहिए। वर्कशीट पर इस परिभाषित सीमा के बाहर रहने वाले किसी भी डेटा को प्रिंट कार्य के दौरान पूरी तरह से अनदेखा कर दिया जाता है। विशाल कच्चे स्रोत डेटा को प्रिंट किए बिना सारांश तालिकाओं को प्रिंट करने के लिए यह महत्वपूर्ण है।"}},
{type:"mcq",diff:"medium",en:{q:"Which feature allows you to keep specific rows or columns visible at all times while scrolling through a large spreadsheet?",opts:["Split Window","Wrap Text","Freeze Panes","Lock Cells"],ans:2,exp:"'Freeze Panes' is an interface feature located under the View tab. It locks specified rows (usually headers) at the top, or columns on the left, ensuring they remain firmly on-screen as the user scrolls horizontally or vertically through hundreds of rows of data. This maintains context for the data being viewed."},hi:{q:"कौन सी सुविधा आपको बड़े स्प्रेडशीट में स्क्रॉल करते समय विशिष्ट पंक्तियों या कॉलमों को हर समय दृश्यमान रखने की अनुमति देती है?",opts:["स्प्लिट विंडो","रैप टेक्स्ट","फ़्रीज़ पैन (Freeze Panes)","लॉक सेल"],ans:2,exp:"'फ़्रीज़ पैन (Freeze Panes)' एक इंटरफ़ेस सुविधा है जो दृश्य (View) टैब के अंतर्गत स्थित है। यह निर्दिष्ट पंक्तियों (आमतौर पर हेडर) को शीर्ष पर, या बाईं ओर कॉलम को लॉक करता है, यह सुनिश्चित करता है कि उपयोगकर्ता सैकड़ों पंक्तियों के डेटा के माध्यम से क्षैतिज या लंबवत रूप से स्क्रॉल करते हुए दृढ़ता से स्क्रीन पर बने रहें। यह देखे जा रहे डेटा के लिए संदर्भ बनाए रखता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which chart type is best suited to display the contribution of individual parts to a whole (percentages)?",opts:["Column Chart","Pie Chart","Scatter Plot","Radar Chart"],ans:1,exp:"A Pie Chart represents a single data series where the entire circle constitutes 100%. It is divided into conceptual 'slices' corresponding to different categories. By visually comparing the slice angles/areas, viewers can instantly grasp the proportional breakdown and understand each category's contribution to the total value."},hi:{q:"कौन सा चार्ट प्रकार व्यक्तिगत भागों के एक पूरे (प्रतिशत) में योगदान प्रदर्शित करने के लिए सबसे उपयुक्त है?",opts:["कॉलम चार्ट","पाई चार्ट","स्कैटर प्लॉट","रडार चार्ट"],ans:1,exp:"एक पाई चार्ट एक एकल डेटा श्रृंखला का प्रतिनिधित्व करता है जहां संपूर्ण चक्र 100% का गठन करता है। इसे विभिन्न श्रेणियों के अनुरूप वैचारिक 'स्लाइस' में विभाजित किया गया है। स्लाइस कोणों/क्षेत्रों की दृष्टि से तुलना करके, दर्शक तुरंत आनुपातिक टूटने को समझ सकते हैं और कुल मूल्य में प्रत्येक श्रेणी के योगदान को समझ सकते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"In Excel, what does the 'Text to Columns' feature do?",opts:["It changes paragraph text into a table layout","It splits data contained in a single column into multiple separate columns based on a delimiter","It translates English text into binary columns","It merges multiple columns of text into one"],ans:1,exp:"The 'Text to Columns' tool parses strings of text residing in a single cell and separates them across multiple adjacent columns. The user specifies a delimiter—such as a comma, space, or tab character—and Excel breaks the string wherever that character appears, converting disorganized raw strings into neatly structured tabular data."},hi:{q:"Excel में, 'Text to Columns' सुविधा क्या करती है?",opts:["यह पैराग्राफ टेक्स्ट को टेबल लेआउट में बदल देता है","यह एक डिलीमीटर के आधार पर एकल कॉलम में निहित डेटा को कई अलग-अलग कॉलम में विभाजित करता है","यह अंग्रेजी पाठ को बाइनरी कॉलम में अनुवादित करता है","यह टेक्स्ट के कई कॉलम को एक में मिलाता है"],ans:1,exp:"'Text to Columns' टूल एकल सेल में रहने वाले टेक्स्ट के स्ट्रिंग्स को पार्स करता है और उन्हें कई आसन्न कॉलम में अलग करता है। उपयोगकर्ता एक डिलीमीटर निर्दिष्ट करता है—जैसे कि अल्पविराम, स्थान, या टैब वर्ण—और Excel स्ट्रिंग को जहां भी वह वर्ण दिखाई देता है, तोड़ देता है, असंगठित कच्चे स्ट्रिंग्स को बड़े करीने से संरचित सारणीबद्ध डेटा में परिवर्तित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary function of a Macro in MS Excel?",opts:["To provide a firewall against viruses","To record and automate a repetitive series of actions and commands","To create complex database relationships","To automatically detect spelling errors"],ans:1,exp:"A Macro is a sequence of instructions and keystrokes recorded by Excel and stored using the VBA (Visual Basic for Applications) programming language. By executing the macro, users can instantly replay those identical steps—such as applying intricate formatting or sorting data—saving massive amounts of time on highly repetitive tasks."},hi:{q:"MS Excel में मैक्रो (Macro) का प्राथमिक कार्य क्या है?",opts:["वायरस के खिलाफ फ़ायरवॉल प्रदान करने के लिए","कार्यों और आदेशों की दोहराव वाली श्रृंखला को रिकॉर्ड और स्वचालित करने के लिए","जटिल डेटाबेस संबंध बनाने के लिए","वर्तनी त्रुटियों का स्वचालित रूप से पता लगाने के लिए"],ans:1,exp:"मैक्रो Excel द्वारा रिकॉर्ड किए गए निर्देशों और कीस्ट्रोक्स का एक क्रम है और इसे VBA (विजुअल बेसिक फॉर एप्लीकेशन) प्रोग्रामिंग भाषा का उपयोग करके संग्रहीत किया जाता है। मैक्रो को निष्पादित करके, उपयोगकर्ता उन समान चरणों को तुरंत फिर से चला सकते हैं—जैसे जटिल स्वरूपण लागू करना या डेटा को छांटना—अत्यधिक दोहराए जाने वाले कार्यों पर भारी मात्रा में समय बचाना।"}},
{type:"mcq",diff:"medium",en:{q:"Which functionality ensures that users can only enter specific types of data (like dates or numbers between 1 and 10) into a cell?",opts:["Data Protection","Conditional Formatting","Data Validation","Scenario Manager"],ans:2,exp:"Data Validation restricts the type, format, or exact value of data that can be input into a designated cell. By setting validation rules, an administrator can enforce data integrity. For example, rejecting text entries when a number is required, or providing a drop-down list of acceptable values, thereby preventing data entry errors at the source."},hi:{q:"कौन सी कार्यक्षमता यह सुनिश्चित करती है कि उपयोगकर्ता एक सेल में केवल विशिष्ट प्रकार के डेटा (जैसे दिनांक या 1 और 10 के बीच की संख्या) दर्ज कर सकते हैं?",opts:["डेटा संरक्षण","सशर्त स्वरूपण (Conditional Formatting)","डेटा सत्यापन (Data Validation)","परिदृश्य प्रबंधक (Scenario Manager)"],ans:2,exp:"डेटा सत्यापन उस डेटा के प्रकार, प्रारूप या सटीक मान को प्रतिबंधित करता है जिसे किसी निर्दिष्ट सेल में इनपुट किया जा सकता है। सत्यापन नियम निर्धारित करके, एक व्यवस्थापक डेटा अखंडता को लागू कर सकता है। उदाहरण के लिए, संख्या की आवश्यकता होने पर टेक्स्ट प्रविष्टियों को अस्वीकार करना, या स्वीकार्य मानों की ड्रॉप-डाउन सूची प्रदान करना, जिससे स्रोत पर डेटा प्रविष्टि त्रुटियों को रोका जा सके।"}},
{type:"mcq",diff:"medium",en:{q:"Which function counts the total number of empty cells inside a specific range?",opts:["COUNT()","COUNTA()","COUNTBLANK()","COUNTEMPTY()"],ans:2,exp:"The COUNTBLANK() function scans a defined range and tallies exactly how many cells contain absolutely no data. This is particularly valuable for auditing large datasets to identify missing information, incomplete survey responses, or un-entered metrics that might skew analytical results."},hi:{q:"कौन सा फ़ंक्शन एक विशिष्ट सीमा के अंदर खाली सेल की कुल संख्या की गणना करता है?",opts:["COUNT()","COUNTA()","COUNTBLANK()","COUNTEMPTY()"],ans:2,exp:"COUNTBLANK() फ़ंक्शन एक परिभाषित सीमा को स्कैन करता है और टैली करता है कि वास्तव में कितने सेल में बिल्कुल कोई डेटा नहीं है। यह लापता जानकारी, अधूरे सर्वेक्षण प्रतिक्रियाओं, या अन-प्रवेशित मैट्रिक्स की पहचान करने के लिए बड़े डेटासेट का ऑडिट करने के लिए विशेष रूप से मूल्यवान है जो विश्लेषणात्मक परिणामों को तिरछा कर सकते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which logical operator implies 'Not Equal To' in an MS Excel formula?",opts:["!==","=!","<>","><"],ans:2,exp:"In Excel syntax, the 'Not Equal To' logic is expressed using back-to-back angle brackets: <>. It is frequently used in logical tests, such as within an IF statement. For instance, '=IF(A1<>B1, \"Mismatch\", \"Match\")' checks if the contents of A1 differ from B1, returning \"Mismatch\" if they are not identical."},hi:{q:"MS Excel सूत्र में कौन सा तार्किक ऑपरेटर 'के बराबर नहीं (Not Equal To)' का तात्पर्य है?",opts:["!==","=!","<>","><"],ans:2,exp:"Excel सिंटैक्स में, 'के बराबर नहीं' तर्क को बैक-टू-बैक कोण कोष्ठक: <> का उपयोग करके व्यक्त किया जाता है। इसका उपयोग अक्सर तार्किक परीक्षणों में किया जाता है, जैसे कि IF कथन के भीतर। उदाहरण के लिए, '=IF(A1<>B1, \"Mismatch\", \"Match\")' जांचता है कि क्या A1 की सामग्री B1 से भिन्न है, यदि वे समान नहीं हैं तो \"Mismatch\" लौटाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the LEN() function do in Excel?",opts:["Calculates the loan amount","Returns the number of characters in a text string","Calculates the geometric length of a cell","Converts a string to lowercase"],ans:1,exp:"The LEN() function stands for 'Length' and is used to compute the precise number of characters present within a text string or a referenced cell. It counts every letter, number, punctuation mark, and crucially, every space character. For example, '=LEN(\"Hello \")' returns 6 because of the trailing space."},hi:{q:"Excel में LEN() फ़ंक्शन क्या करता है?",opts:["ऋण राशि की गणना करता है","एक टेक्स्ट स्ट्रिंग में वर्णों की संख्या देता है","सेल की ज्यामितीय लंबाई की गणना करता है","एक स्ट्रिंग को लोअरकेस में परिवर्तित करता है"],ans:1,exp:"LEN() फ़ंक्शन 'लेंथ' के लिए खड़ा है और इसका उपयोग टेक्स्ट स्ट्रिंग या संदर्भित सेल के भीतर मौजूद वर्णों की सटीक संख्या की गणना करने के लिए किया जाता है। यह हर अक्षर, संख्या, विराम चिह्न और महत्वपूर्ण रूप से, हर अंतरिक्ष चरित्र की गणना करता है। उदाहरण के लिए, अनुगामी स्थान के कारण '=LEN(\"Hello \")' 6 देता है।"}},
{type:"mcq",diff:"medium",en:{q:"How do you properly reference cell A1 situated on a different worksheet named 'Data'?",opts:["Data:A1","Data!A1","Data@A1","Data#A1"],ans:1,exp:"To reference a cell residing on an entirely different worksheet within the same workbook, Excel syntax requires the worksheet name followed immediately by an exclamation mark (!), and then the cell reference. Therefore, 'Data!A1' accurately links the formula to cell A1 located specifically on the sheet titled 'Data'."},hi:{q:"आप 'Data' नामक भिन्न वर्कशीट पर स्थित सेल A1 को ठीक से कैसे संदर्भित करते हैं?",opts:["Data:A1","Data!A1","Data@A1","Data#A1"],ans:1,exp:"एक ही वर्कबुक के भीतर पूरी तरह से अलग वर्कशीट पर रहने वाले सेल को संदर्भित करने के लिए, Excel सिंटैक्स को वर्कशीट नाम की आवश्यकता होती है जिसके तुरंत बाद विस्मयादिबोधक चिह्न (!) होता है, और फिर सेल संदर्भ होता है। इसलिए, 'Data!A1' सटीक रूप से 'Data' नामक शीट पर विशेष रूप से स्थित सेल A1 से सूत्र को जोड़ता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the output of the function =MID(\"SPREADSHEET\", 7, 5)?",opts:["SPREAD","SHEET","READS","HEET"],ans:1,exp:"The MID() function extracts a designated number of characters from the absolute middle of a text string, based on a starting position. The syntax is MID(text, start_num, num_chars). Starting at character 7 ('S') in 'SPREADSHEET', and extracting exactly 5 characters yields the substring 'SHEET'."},hi:{q:"फ़ंक्शन =MID(\"SPREADSHEET\", 7, 5) का आउटपुट क्या है?",opts:["SPREAD","SHEET","READS","HEET"],ans:1,exp:"MID() फ़ंक्शन प्रारंभिक स्थिति के आधार पर, एक टेक्स्ट स्ट्रिंग के पूर्ण मध्य से वर्णों की निर्दिष्ट संख्या निकालता है। सिंटैक्स MID(text, start_num, num_chars) है। 'SPREADSHEET' में वर्ण 7 ('S') से शुरू होकर, और ठीक 5 वर्ण निकालने से सबस्ट्रिंग 'SHEET' प्राप्त होता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which feature allows you to temporarily hide rows that do not meet a specific criteria without deleting the data?",opts:["Sorting","Formatting","Filtering","Validation"],ans:2,exp:"Filtering is a core data-analysis tool that conditionally hides rows of data. When a filter is applied via drop-down arrows on column headers, Excel temporarily conceals any row that fails to match the selected criteria (e.g., hiding all sales below $500). The data remains perfectly intact and can be revealed by clearing the filter."},hi:{q:"कौन सी सुविधा आपको डेटा को हटाए बिना उन पंक्तियों को अस्थायी रूप से छिपाने की अनुमति देती है जो किसी विशिष्ट मानदंड को पूरा नहीं करती हैं?",opts:["Sorting","Formatting","Filtering","Validation"],ans:2,exp:"फ़िल्टरिंग (Filtering) एक मुख्य डेटा-विश्लेषण उपकरण है जो सशर्त रूप से डेटा की पंक्तियों को छिपाता है। जब कॉलम हेडर पर ड्रॉप-डाउन तीरों के माध्यम से एक फ़िल्टर लागू किया जाता है, तो Excel अस्थायी रूप से उस पंक्ति को छुपा देता है जो चयनित मानदंडों से मेल खाने में विफल रहती है (उदा., $500 से कम की सभी बिक्री को छिपाना)। डेटा पूरी तरह से अक्षुण्ण रहता है और फ़िल्टर साफ़ करके प्रकट किया जा सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following functions allows you to test multiple conditions, returning TRUE only if ALL conditions are true?",opts:["OR()","IF()","AND()","NOT()"],ans:2,exp:"The AND() logical function evaluates multiple arguments (conditions). It acts as a strict gateway, returning a boolean TRUE exclusively if every single condition evaluated is true. If even one condition fails and evaluates to FALSE, the AND() function instantly returns FALSE. It is heavily used inside IF() statements for complex logic."},hi:{q:"निम्नलिखित में से कौन सा फ़ंक्शन आपको कई शर्तों का परीक्षण करने की अनुमति देता है, यदि सभी शर्तें सत्य हों तभी TRUE लौटाता है?",opts:["OR()","IF()","AND()","NOT()"],ans:2,exp:"AND() तार्किक फ़ंक्शन कई तर्कों (स्थितियों) का मूल्यांकन करता है। यह एक सख्त प्रवेश द्वार के रूप में कार्य करता है, बूलियन TRUE विशेष रूप से तभी लौटाता है जब मूल्यांकन की गई हर एक स्थिति सत्य हो। यदि एक भी शर्त विफल हो जाती है और FALSE का मूल्यांकन करती है, तो AND() फ़ंक्शन तुरंत FALSE लौटा देता है। जटिल तर्क के लिए इसका भारी उपयोग IF() बयानों के अंदर किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"If you apply the 'Sort' command on a column containing text, what order does 'Ascending' represent?",opts:["Z to A","Largest to Smallest","A to Z","Oldest to Newest"],ans:2,exp:"When executing a 'Sort Ascending' operation on a column strictly containing text data, Excel organizes the rows alphabetically from A to Z. This alphabetic sorting groups similar text entries together, placing strings starting with 'A' at the top and progressing down to 'Z', which is vital for organizing names or textual categories."},hi:{q:"यदि आप टेक्स्ट वाले कॉलम पर 'सॉर्ट' (Sort) कमांड लागू करते हैं, तो 'आरोही' (Ascending) किस क्रम का प्रतिनिधित्व करता है?",opts:["Z से A","सबसे बड़ा से सबसे छोटा","A से Z","सबसे पुराना से सबसे नया"],ans:2,exp:"जब सख्ती से टेक्स्ट डेटा वाले कॉलम पर 'सॉर्ट असेंडिंग' ऑपरेशन निष्पादित किया जाता है, तो Excel पंक्तियों को A से Z तक वर्णानुक्रम में व्यवस्थित करता है। यह वर्णमाला छँटाई समान टेक्स्ट प्रविष्टियों को एक साथ समूहित करती है, जो 'A' से शुरू होने वाले स्ट्रिंग्स को शीर्ष पर रखती है और 'Z' तक नीचे की ओर बढ़ती है, जो नाम या पाठ्य श्रेणियों को व्यवस्थित करने के लिए महत्वपूर्ण है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the acronym 'VLOOKUP' stand for?",opts:["Value Lookup","Vertical Lookup","Variable Lookup","Visual Lookup"],ans:1,exp:"The 'V' in VLOOKUP denotes 'Vertical'. This indispensable function searches vertically down the very first (leftmost) column of a designated table array until it finds a specified lookup value. Upon finding a match, it moves horizontally across that row to retrieve a corresponding value from a specified column index number."},hi:{q:"संक्षिप्त नाम 'VLOOKUP' का क्या अर्थ है?",opts:["Value Lookup","Vertical Lookup","Variable Lookup","Visual Lookup"],ans:1,exp:"VLOOKUP में 'V' 'Vertical (ऊर्ध्वाधर)' को दर्शाता है। यह अपरिहार्य फ़ंक्शन एक निर्दिष्ट तालिका सरणी के पहले (सबसे बाएँ) कॉलम के नीचे लंबवत खोज करता है जब तक कि उसे एक निर्दिष्ट लुकअप मान नहीं मिल जाता। एक मैच खोजने पर, यह एक निर्दिष्ट कॉलम इंडेक्स नंबर से संबंधित मान प्राप्त करने के लिए उस पंक्ति में क्षैतिज रूप से चलता है।"}},
{type:"mcq",diff:"medium",en:{q:"To format a cell so that a negative number automatically appears in red font, which tool should be used?",opts:["Format Painter","AutoFormat","Conditional Formatting","Cell Styles"],ans:2,exp:"Conditional Formatting applies specific cell formatting (like font color, background fills, or icons) dynamically based on the actual value contained within the cell. By creating a rule that targets 'cells less than 0' and setting the format to a red font, Excel automates visual alerts for negative financial figures or variances."},hi:{q:"एक सेल को इस तरह से फ़ॉर्मेट करने के लिए कि कोई ऋणात्मक (negative) संख्या स्वचालित रूप से लाल फ़ॉन्ट में दिखाई दे, किस टूल का उपयोग किया जाना चाहिए?",opts:["Format Painter","AutoFormat","Conditional Formatting","Cell Styles"],ans:2,exp:"सशर्त स्वरूपण (Conditional Formatting) सेल के भीतर निहित वास्तविक मूल्य के आधार पर गतिशील रूप से विशिष्ट सेल स्वरूपण (जैसे फ़ॉन्ट रंग, पृष्ठभूमि भरने, या आइकन) लागू करता है। एक नियम बनाकर जो '0 से कम कोशिकाओं' को लक्षित करता है और प्रारूप को लाल फ़ॉन्ट में सेट करता है, Excel नकारात्मक वित्तीय आंकड़ों या भिन्नताओं के लिए दृश्य अलर्ट को स्वचालित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"In MS Excel, what is the default alignment for numerical data entered into a cell?",opts:["Left aligned","Center aligned","Right aligned","Justified"],ans:2,exp:"By default engineering design, MS Excel aligns any purely numerical data, dates, and times strictly to the right side of the cell. This right-alignment ensures that decimal points and unit placeholders line up correctly in a column, facilitating easier mental calculation. Conversely, text entries are left-aligned by default."},hi:{q:"MS Excel में, एक सेल में दर्ज संख्यात्मक डेटा के लिए डिफ़ॉल्ट संरेखण (alignment) क्या है?",opts:["बाएं संरेखित (Left aligned)","केंद्र संरेखित (Center aligned)","दाएं संरेखित (Right aligned)","न्यायोचित (Justified)"],ans:2,exp:"डिफ़ॉल्ट इंजीनियरिंग डिज़ाइन द्वारा, MS Excel किसी भी विशुद्ध रूप से संख्यात्मक डेटा, दिनांक और समय को सेल के दाईं ओर सख्ती से संरेखित करता है। यह दायां-संरेखण यह सुनिश्चित करता है कि एक कॉलम में दशमलव बिंदु और इकाई प्लेसहोल्डर सही ढंग से लाइन अप करें, जिससे आसान मानसिक गणना की सुविधा मिलती है। इसके विपरीत, टेक्स्ट प्रविष्टियां डिफ़ॉल्ट रूप से बाएं-संरेखित होती हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following functions will extract the year strictly from a date formatted cell?",opts:["YEAR()","DATE()","GETYEAR()","EXTRACT()"],ans:0,exp:"The YEAR() function is categorized under Date & Time functions. When supplied with a valid date serial number or cell reference, it computes and returns exactly the year as a four-digit integer (e.g., 2024). It strips away the day and month data, which is highly useful for grouping datasets annually."},hi:{q:"निम्नलिखित में से कौन सा फ़ंक्शन दिनांक स्वरूपित सेल से सख्ती से वर्ष निकालेगा?",opts:["YEAR()","DATE()","GETYEAR()","EXTRACT()"],ans:0,exp:"YEAR() फ़ंक्शन को दिनांक और समय फ़ंक्शन के अंतर्गत वर्गीकृत किया गया है। जब एक मान्य दिनांक सीरियल नंबर या सेल संदर्भ के साथ आपूर्ति की जाती है, तो यह गणना करता है और बिल्कुल वर्ष को चार अंकों के पूर्णांक (उदा., 2024) के रूप में देता है। यह दिन और महीने के डेटा को हटा देता है, जो सालाना डेटासेट को समूहीकृत करने के लिए अत्यधिक उपयोगी है।"}},
{type:"tf",diff:"medium",en:{q:"Conditional formatting allows a cell's background color to change dynamically based on the value inside the cell.",opts:["True","False"],ans:0,exp:"True. Conditional Formatting evaluates cell contents against predefined rules. If the rule evaluates to TRUE (e.g., 'Value is greater than 100'), Excel automatically applies designated formatting such as cell fill color, font style, or data bars, creating responsive visual dashboards."},hi:{q:"सशर्त स्वरूपण (Conditional formatting) एक सेल के पृष्ठभूमि रंग को सेल के अंदर के मान के आधार पर गतिशील रूप से बदलने की अनुमति देता है।",opts:["सही","गलत"],ans:0,exp:"सही। सशर्त स्वरूपण पूर्वनिर्धारित नियमों के विरुद्ध सेल सामग्री का मूल्यांकन करता है। यदि नियम TRUE (उदा., 'मूल्य 100 से अधिक है') का मूल्यांकन करता है, तो Excel स्वचालित रूप से उत्तरदायी दृश्य डैशबोर्ड बनाते हुए सेल भरण रंग, फ़ॉन्ट शैली या डेटा बार जैसे निर्दिष्ट स्वरूपण लागू करता है।"}},
{type:"tf",diff:"medium",en:{q:"Absolute cell references dynamically alter their row and column indicators when pasted into a new location.",opts:["True","False"],ans:1,exp:"False. The primary function of an absolute reference (identified by the dollar signs, e.g., $B$5) is specifically to prevent any dynamic alteration. It guarantees that no matter where the formula is copied or pasted within the worksheet, the formula will continuously reference the exact same fixed cell $B$5."},hi:{q:"एक नए स्थान पर पेस्ट किए जाने पर पूर्ण (absolute) सेल संदर्भ गतिशील रूप से अपनी पंक्ति और कॉलम संकेतक को बदल देते हैं।",opts:["सही","गलत"],ans:1,exp:"गलत। एक पूर्ण संदर्भ (डॉलर के संकेतों द्वारा पहचाना जाता है, उदा., $B$5) का प्राथमिक कार्य विशेष रूप से किसी भी गतिशील परिवर्तन को रोकना है। यह गारंटी देता है कि वर्कशीट के भीतर सूत्र को कॉपी या पेस्ट किया जाता है, सूत्र लगातार सटीक एक ही निश्चित सेल $B$5 को संदर्भित करेगा।"}},
{type:"mcq",diff:"hard",en:{q:"In a VLOOKUP formula, what does setting the fourth argument (range_lookup) to FALSE guarantee?",opts:["It guarantees an approximate match","It guarantees the lookup searches horizontally","It guarantees that an exact match must be found, otherwise returning an error","It guarantees that the formula will ignore text values"],ans:2,exp:"The range_lookup parameter dictates the matching precision. Providing FALSE (or 0) instructs VLOOKUP to search strictly for an exact match to the lookup value. If an identical match does not exist within the first column of the array, the function deliberately fails and outputs the #N/A error to ensure data accuracy."},hi:{q:"VLOOKUP सूत्र में, चौथे तर्क (range_lookup) को FALSE पर सेट करने से क्या गारंटी मिलती है?",opts:["यह एक अनुमानित मैच की गारंटी देता है","यह गारंटी देता है कि लुकअप क्षैतिज रूप से खोजता है","यह गारंटी देता है कि एक सटीक मिलान पाया जाना चाहिए, अन्यथा एक त्रुटि वापस आ जाएगी","यह गारंटी देता है कि सूत्र पाठ मानों को अनदेखा करेगा"],ans:2,exp:"range_lookup पैरामीटर मिलान सटीकता को निर्धारित करता है। FALSE (या 0) प्रदान करना VLOOKUP को लुकअप मान के सटीक मिलान के लिए सख्ती से खोजने का निर्देश देता है। यदि सरणी के पहले कॉलम के भीतर एक समान मिलान मौजूद नहीं है, तो फ़ंक्शन जानबूझकर विफल हो जाता है और डेटा सटीकता सुनिश्चित करने के लिए #N/A त्रुटि आउटपुट करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which unique keyboard combination must be pressed to execute a traditional Array Formula in MS Excel?",opts:["Ctrl + Alt + Enter","Ctrl + Shift + Enter","Shift + Alt + Enter","Ctrl + Windows + Enter"],ans:1,exp:"In legacy versions of Excel, complex Array Formulas—which execute calculations across multiple ranges to yield single or multiple results—must be committed using the 'Ctrl + Shift + Enter' (CSE) key combination. This action wraps the entire formula in curly braces {}, signaling to Excel's engine to process the matrices appropriately."},hi:{q:"MS Excel में पारंपरिक ऐरे फॉर्मूला को निष्पादित करने के लिए कौन सा अद्वितीय कीबोर्ड संयोजन दबाया जाना चाहिए?",opts:["Ctrl + Alt + Enter","Ctrl + Shift + Enter","Shift + Alt + Enter","Ctrl + Windows + Enter"],ans:1,exp:"Excel के पुराने संस्करणों में, जटिल ऐरे फॉर्मूला—जो एकल या एकाधिक परिणाम प्राप्त करने के लिए कई श्रेणियों में गणना निष्पादित करते हैं—को 'Ctrl + Shift + Enter' (CSE) कुंजी संयोजन का उपयोग करके प्रतिबद्ध होना चाहिए। यह क्रिया पूरे सूत्र को घुंघराले ब्रेसिज़ {} में लपेटती है, जो Excel के इंजन को मैट्रिक्स को उचित रूप से संसाधित करने का संकेत देती है।"}},
{type:"mcq",diff:"hard",en:{q:"Which Advanced Data tool allows you to reverse engineer a formula to find the required input value that produces a specific target result?",opts:["Data Validation","Goal Seek","Macro Recorder","VLOOKUP"],ans:1,exp:"'Goal Seek' is a fundamental 'What-If Analysis' tool. Instead of tweaking inputs manually to see how a formula's output changes, Goal Seek works backwards. The user defines the desired target output for a formula cell, and Goal Seek automatically calculates and alters an input variable cell until that exact target is reached."},hi:{q:"कौन सा उन्नत डेटा टूल (Advanced Data tool) आपको एक विशिष्ट लक्ष्य परिणाम उत्पन्न करने वाले आवश्यक इनपुट मान को खोजने के लिए एक सूत्र को रिवर्स इंजीनियर करने की अनुमति देता है?",opts:["Data Validation","Goal Seek","Macro Recorder","VLOOKUP"],ans:1,exp:"'Goal Seek' एक मौलिक 'व्हाट-इफ एनालिसिस' टूल है। मैन्युअल रूप से इनपुट को ट्विक करने के बजाय यह देखने के लिए कि फॉर्मूले का आउटपुट कैसे बदलता है, गोल सीक पीछे की ओर काम करता है। उपयोगकर्ता एक सूत्र सेल के लिए वांछित लक्ष्य आउटपुट को परिभाषित करता है, और गोल सीक स्वचालित रूप से एक इनपुट चर सेल की गणना करता है और बदलता है जब तक कि वह सटीक लक्ष्य नहीं पहुंच जाता।"}},
{type:"mcq",diff:"hard",en:{q:"What function is specifically engineered to handle, trap, and substitute standard Excel formula errors (like #DIV/0!) with a custom value?",opts:["ISERROR()","IFERROR()","ERROR.TYPE()","CHECKERROR()"],ans:1,exp:"The IFERROR() function provides elegant error handling. It evaluates a specified formula; if that formula calculates normally, it returns the standard result. However, if the calculation generates any standard Excel error (e.g., #N/A, #VALUE!, #DIV/0!), it intercepts the error and outputs an alternative user-defined value, such as a blank string \"\" or \"Error\"."},hi:{q:"कौन सा फ़ंक्शन विशेष रूप से कस्टम मान के साथ मानक Excel सूत्र त्रुटियों (जैसे #DIV/0!) को संभालने, फंसाने और प्रतिस्थापित करने के लिए इंजीनियर किया गया है?",opts:["ISERROR()","IFERROR()","ERROR.TYPE()","CHECKERROR()"],ans:1,exp:"IFERROR() फ़ंक्शन सुरुचिपूर्ण त्रुटि हैंडलिंग प्रदान करता है। यह एक निर्दिष्ट सूत्र का मूल्यांकन करता है; यदि वह सूत्र सामान्य रूप से गणना करता है, तो यह मानक परिणाम देता है। हालाँकि, यदि गणना कोई मानक Excel त्रुटि (उदा., #N/A, #VALUE!, #DIV/0!) उत्पन्न करती है, तो यह त्रुटि को रोकता है और एक वैकल्पिक उपयोगकर्ता-परिभाषित मान आउटपुट करता है, जैसे कि एक खाली स्ट्रिंग \"\" या \"त्रुटि\"।"}},
{type:"mcq",diff:"hard",en:{q:"In Pivot Tables, what interactive graphical tool is used to quickly filter data ranges with a single click?",opts:["Macros","Slicers","Sparklines","Data Bars"],ans:1,exp:"Slicers are intuitive, visual filtering components introduced in modern Excel for Pivot Tables and Pivot Charts. Rather than using clunky drop-down menus to filter categories, a Slicer provides a panel of clickable buttons representing the data items. Selecting a button instantly filters the Pivot Table, providing a highly visual, user-friendly dashboard experience."},hi:{q:"पिवट टेबल्स में, एक क्लिक के साथ डेटा रेंज को जल्दी से फ़िल्टर करने के लिए किस इंटरैक्टिव ग्राफिकल टूल का उपयोग किया जाता है?",opts:["मैक्रोज़","स्लाइसर्स (Slicers)","स्पार्कलाइन्स","डेटा बार"],ans:1,exp:"स्लाइसर आधुनिक Excel में पिवट टेबल्स और पिवट चार्ट्स के लिए पेश किए गए सहज, विज़ुअल फ़िल्टरिंग घटक हैं। श्रेणियों को फ़िल्टर करने के लिए क्लंकी ड्रॉप-डाउन मेनू का उपयोग करने के बजाय, स्लाइसर डेटा आइटम का प्रतिनिधित्व करने वाले क्लिक करने योग्य बटन का एक पैनल प्रदान करता है। बटन का चयन करने से तुरंत पिवट टेबल फ़िल्टर हो जाता है, जो एक अत्यधिक दृश्यमान, उपयोगकर्ता के अनुकूल डैशबोर्ड अनुभव प्रदान करता है।"}},
{type:"mcq",diff:"hard",en:{q:"When creating a custom number format, what does the code format '0.00' mandate?",opts:["It forces the cell to display only text","It rounds the number to the nearest whole integer","It enforces the display of exactly two decimal places, padding with zeros if necessary","It multiplies the value by 100"],ans:2,exp:"In Excel's custom formatting syntax, the '0' serves as a strict digit placeholder. The format '0.00' dictates that the numerical value must always display at least one digit before the decimal and exactly two digits after it. For example, entering '5' will be visually forced to display as '5.00'."},hi:{q:"कस्टम संख्या प्रारूप बनाते समय, कोड प्रारूप '0.00' क्या आदेश देता है?",opts:["यह सेल को केवल टेक्स्ट प्रदर्शित करने के लिए बाध्य करता है","यह संख्या को निकटतम पूर्ण पूर्णांक तक पूर्ण (राउंड) करता है","यह ठीक दो दशमलव स्थानों का प्रदर्शन लागू करता है, यदि आवश्यक हो तो शून्य के साथ पैडिंग करता है","यह मान को 100 से गुणा करता है"],ans:2,exp:"Excel के कस्टम स्वरूपण सिंटैक्स में, '0' एक सख्त अंक प्लेसहोल्डर के रूप में कार्य करता है। '0.00' प्रारूप यह निर्धारित करता है कि संख्यात्मक मान हमेशा दशमलव से पहले कम से कम एक अंक और उसके बाद ठीक दो अंक प्रदर्शित करना चाहिए। उदाहरण के लिए, '5' दर्ज करने पर दृष्टिगत रूप से '5.00' प्रदर्शित करने के लिए मजबूर किया जाएगा।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following functions evaluates multiple criteria across ranges and SUMS only the values that meet ALL the specified criteria?",opts:["SUM()","SUMIF()","SUMIFS()","DSUM()"],ans:2,exp:"While SUMIF() handles only a single condition, the SUMIFS() function is architected for complex, multi-layered logical aggregations. It computes the sum of a designated range only where the corresponding rows pass multiple independent logical criteria arrays simultaneously (e.g., Sum sales IF Region='East' AND Product='Apples')."},hi:{q:"निम्नलिखित में से कौन सा फ़ंक्शन श्रेणियों में कई मानदंडों का मूल्यांकन करता है और केवल उन मानों को जोड़ता (SUMS) है जो सभी निर्दिष्ट मानदंडों को पूरा करते हैं?",opts:["SUM()","SUMIF()","SUMIFS()","DSUM()"],ans:2,exp:"जबकि SUMIF() केवल एक ही स्थिति को संभालता है, SUMIFS() फ़ंक्शन को जटिल, बहु-स्तरीय तार्किक एकत्रीकरण के लिए तैयार किया गया है। यह एक निर्दिष्ट सीमा के योग की गणना केवल तभी करता है जब संबंधित पंक्तियाँ एक साथ कई स्वतंत्र तार्किक मानदंड सरणियों को पार करती हैं (उदा., योग बिक्री यदि क्षेत्र = 'पूर्व' और उत्पाद = 'सेब')।"}},
{type:"mcq",diff:"hard",en:{q:"What distinguishes the SEARCH() function from the FIND() function in Excel?",opts:["SEARCH supports wildcard characters and is not case-sensitive","FIND supports wildcard characters and is not case-sensitive","SEARCH is strictly used for numerical values","FIND returns text, SEARCH returns a number"],ans:0,exp:"Both functions locate the numerical starting position of a substring within a larger text string. However, FIND() is strictly case-sensitive and rejects wildcards. Conversely, SEARCH() ignores case sensitivity (treating 'a' and 'A' equally) and fully supports wildcard characters like '*' and '?' for highly flexible pattern matching."},hi:{q:"Excel में कौन सी बात SEARCH() फ़ंक्शन को FIND() फ़ंक्शन से अलग करती है?",opts:["SEARCH वाइल्डकार्ड वर्णों का समर्थन करता है और केस-संवेदी (case-sensitive) नहीं है","FIND वाइल्डकार्ड वर्णों का समर्थन करता है और केस-संवेदी नहीं है","SEARCH का उपयोग कड़ाई से संख्यात्मक मानों के लिए किया जाता है","FIND पाठ देता है, SEARCH एक संख्या देता है"],ans:0,exp:"दोनों फ़ंक्शन एक बड़े टेक्स्ट स्ट्रिंग के भीतर सबस्ट्रिंग की संख्यात्मक प्रारंभिक स्थिति का पता लगाते हैं। हालाँकि, FIND() कड़ाई से केस-संवेदी है और वाइल्डकार्ड को अस्वीकार करता है। इसके विपरीत, SEARCH() केस संवेदनशीलता को अनदेखा करता है ('a' और 'A' को समान रूप से व्यवहार करता है) और अत्यधिक लचीले पैटर्न मिलान के लिए '*' और '?' जैसे वाइल्डकार्ड वर्णों का पूरी तरह से समर्थन करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which function is used to calculate the periodic payment for an annuity or loan based on constant payments and a constant interest rate?",opts:["FV()","NPER()","PMT()","PV()"],ans:2,exp:"The PMT() function is a core financial function. It computes the fixed periodic payment required to fully amortize a loan over a set number of periods, given a constant interest rate. The required syntax parameters are Rate (interest per period), Nper (total number of periods), and PV (Present Value or total loan amount)."},hi:{q:"निरंतर भुगतान और निरंतर ब्याज दर के आधार पर वार्षिकी या ऋण के लिए आवधिक भुगतान की गणना करने के लिए किस फ़ंक्शन का उपयोग किया जाता है?",opts:["FV()","NPER()","PMT()","PV()"],ans:2,exp:"PMT() फ़ंक्शन एक मुख्य वित्तीय फ़ंक्शन है। यह एक निरंतर ब्याज दर को देखते हुए, निर्धारित अवधि में ऋण को पूरी तरह से चुकाने के लिए आवश्यक निश्चित आवधिक भुगतान की गणना करता है। आवश्यक सिंटैक्स पैरामीटर दर (प्रति अवधि ब्याज), Nper (अवधि की कुल संख्या), और PV (वर्तमान मूल्य या कुल ऋण राशि) हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What occurs when an Excel formula refers back to its own cell, either directly or indirectly?",opts:["A Syntax Error","A Formula Parse Error","A Circular Reference","A Macro Virus warning"],ans:2,exp:"A Circular Reference occurs when a formula within a cell depends on the result of that very same cell to calculate. This creates a potentially infinite, unsolvable loop. Excel immediately halts calculation, issues a warning prompt to the user, and displays 'Circular References' in the bottom Status Bar until the logical flaw is resolved."},hi:{q:"जब कोई Excel सूत्र सीधे या अप्रत्यक्ष रूप से अपने स्वयं के सेल को संदर्भित करता है तो क्या होता है?",opts:["सिंटैक्स त्रुटि","फ़ॉर्मूला पार्स त्रुटि","परिपत्र संदर्भ (Circular Reference)","मैक्रो वायरस चेतावनी"],ans:2,exp:"परिपत्र संदर्भ (Circular Reference) तब होता है जब एक सेल के भीतर एक सूत्र गणना करने के लिए उसी सेल के परिणाम पर निर्भर करता है। यह एक संभावित अनंत, न सुलझने वाला लूप बनाता है। Excel तुरंत गणना रोक देता है, उपयोगकर्ता को एक चेतावनी संकेत जारी करता है, और तार्किक दोष हल होने तक नीचे स्टेटस बार में 'परिपत्र संदर्भ' प्रदर्शित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In advanced Excel indexing, which function is frequently combined with MATCH() to provide a more robust alternative to VLOOKUP?",opts:["HLOOKUP()","CHOOSE()","OFFSET()","INDEX()"],ans:3,exp:"The combination of INDEX() and MATCH() completely overcomes VLOOKUP's critical limitation of only searching left-to-right. MATCH() dynamically finds the relative row/column position of a lookup value, feeding that coordinate into INDEX(), which retrieves the value from any intersecting array position, regardless of column order."},hi:{q:"उन्नत Excel अनुक्रमण में, VLOOKUP को अधिक मजबूत विकल्प प्रदान करने के लिए अक्सर MATCH() के साथ कौन सा कार्य जोड़ा जाता है?",opts:["HLOOKUP()","CHOOSE()","OFFSET()","INDEX()"],ans:3,exp:"INDEX() और MATCH() का संयोजन केवल बाएं से दाएं खोजने की VLOOKUP की महत्वपूर्ण सीमा को पूरी तरह से पार कर जाता है। MATCH() गतिशील रूप से लुकअप मान की सापेक्ष पंक्ति/कॉलम स्थिति का पता लगाता है, उस समन्वय को INDEX() में फीड करता है, जो कॉलम क्रम की परवाह किए बिना किसी भी प्रतिच्छेदन सरणी स्थिति से मान प्राप्त करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following functions dynamically returns a reference to a range that is a specified number of rows and columns from a starting cell?",opts:["INDIRECT()","OFFSET()","ADDRESS()","MATCH()"],ans:1,exp:"The OFFSET() function physically shifts a starting reference. It takes a base cell and moves a specified number of rows (down/up) and columns (right/left) to pinpoint a new target range. It is heavily utilized by advanced users to construct dynamic named ranges that automatically expand when new data rows are added."},hi:{q:"निम्नलिखित में से कौन सा फ़ंक्शन गतिशील रूप से एक श्रेणी का संदर्भ देता है जो एक शुरुआती सेल से निर्दिष्ट पंक्तियों और कॉलम की संख्या है?",opts:["INDIRECT()","OFFSET()","ADDRESS()","MATCH()"],ans:1,exp:"OFFSET() फ़ंक्शन शारीरिक रूप से एक प्रारंभिक संदर्भ को स्थानांतरित करता है। यह एक आधार सेल लेता है और एक नए लक्ष्य सीमा को इंगित करने के लिए निर्दिष्ट पंक्तियों (नीचे/ऊपर) और कॉलम (दाएं/बाएं) को स्थानांतरित करता है। नए डेटा पंक्तियों को जोड़े जाने पर स्वचालित रूप से विस्तार करने वाली गतिशील नामित श्रेणियां (dynamic named ranges) बनाने के लिए उन्नत उपयोगकर्ताओं द्वारा इसका भारी उपयोग किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"What does the feature 'Consolidate Data' do in Excel?",opts:["It compresses the file size of the workbook","It permanently merges several worksheets into one and deletes the originals","It aggregates and summarizes data from multiple separate ranges or worksheets into a single master layout","It runs an antivirus scan on numeric data"],ans:2,exp:"The Data Consolidation tool is used to synthesize large datasets spread across different worksheets or ranges. By applying mathematical functions like SUM or AVERAGE, it rolls up independent, identically structured tables into one summarized master table, allowing for multi-departmental or multi-year data integration."},hi:{q:"Excel में 'Consolidate Data' (डेटा को समेकित करें) सुविधा क्या करती है?",opts:["यह वर्कबुक के फ़ाइल आकार को संकुचित करता है","यह स्थायी रूप से कई वर्कशीट को एक में मिला देता है और मूल को हटा देता है","यह एक ही मास्टर लेआउट में कई अलग-अलग श्रेणियों या वर्कशीट से डेटा को एकत्रित और सारांशित करता है","यह संख्यात्मक डेटा पर एंटीवायरस स्कैन चलाता है"],ans:2,exp:"डेटा समेकन (Data Consolidation) टूल का उपयोग विभिन्न वर्कशीट या श्रेणियों में फैले बड़े डेटासेट को संश्लेषित करने के लिए किया जाता है। SUM या AVERAGE जैसे गणितीय कार्यों को लागू करके, यह स्वतंत्र, समान रूप से संरचित तालिकाओं को एक सारांशित मास्टर तालिका में घुमाता है, जो बहु-विभागीय या बहु-वर्षीय डेटा एकीकरण की अनुमति देता है।"}},
{type:"mcq",diff:"hard",en:{q:"Internally, how does Microsoft Excel store calendar dates?",opts:["As plain text strings (e.g., '10/05/2024')","As hexadecimal code","As sequential integer numbers starting from January 1, 1900","As complex matrices"],ans:2,exp:"To perform date arithmetic, Excel relies on a 'Date Serial Number' system. Every date is stored internally as a sequential whole number. By default, January 1, 1900, is serial number 1. Consequently, January 2, 1900, is 2, allowing formulas to easily add or subtract days by treating dates as simple mathematical integers."},hi:{q:"आंतरिक रूप से, Microsoft Excel कैलेंडर तिथियों को कैसे संग्रहीत करता है?",opts:["सादे टेक्स्ट स्ट्रिंग के रूप में (उदा., '10/05/2024')","हेक्साडेसिमल कोड के रूप में","1 जनवरी, 1900 से शुरू होने वाली क्रमिक पूर्णांक संख्याओं के रूप में","जटिल मैट्रिक्स के रूप में"],ans:2,exp:"दिनांक अंकगणित करने के लिए, Excel 'दिनांक क्रमांक (Date Serial Number)' प्रणाली पर निर्भर करता है। प्रत्येक तिथि को आंतरिक रूप से अनुक्रमिक पूर्ण संख्या के रूप में संग्रहीत किया जाता है। डिफ़ॉल्ट रूप से, 1 जनवरी, 1900, क्रमांक 1 है। नतीजतन, 2 जनवरी, 1900, 2 है, जिससे सूत्रों को तिथियों को साधारण गणितीय पूर्णांक मानकर आसानी से दिन जोड़ने या घटाने की अनुमति मिलती है।"}},
{type:"mcq",diff:"hard",en:{q:"What does a 'Volatile Function' (such as RAND or NOW) do in Excel?",opts:["It crashes the application frequently","It forces the entire workbook to recalculate every time any change is made to any cell","It automatically deletes old data","It only calculates when manually triggered"],ans:1,exp:"A volatile function (like RAND(), TODAY(), NOW(), OFFSET()) inherently lacks a stable state. Whenever any cell in the entire workbook is modified, Excel's calculation engine is forced to completely recalculate every volatile function present. Excessive use of volatile functions in large models causes severe performance lag."},hi:{q:"Excel में एक 'अस्थिर कार्य' (Volatile Function) (जैसे RAND या NOW) क्या करता है?",opts:["यह एप्लिकेशन को बार-बार क्रैश करता है","यह पूरी वर्कबुक को हर बार किसी भी सेल में कोई बदलाव किए जाने पर पुनर्गणना करने के लिए मजबूर करता है","यह स्वचालित रूप से पुराने डेटा को हटा देता है","यह केवल मैन्युअल रूप से ट्रिगर होने पर ही गणना करता है"],ans:1,exp:"एक अस्थिर फ़ंक्शन (जैसे RAND(), TODAY(), NOW(), OFFSET()) में स्वाभाविक रूप से एक स्थिर स्थिति का अभाव होता है। जब भी संपूर्ण वर्कबुक में किसी सेल को संशोधित किया जाता है, तो Excel का गणना इंजन मौजूद प्रत्येक अस्थिर फ़ंक्शन को पूरी तरह से पुनर्गणना करने के लिए मजबूर होता है। बड़े मॉडलों में अस्थिर कार्यों के अत्यधिक उपयोग से प्रदर्शन में गंभीर कमी आती है।"}},
{type:"mcq",diff:"hard",en:{q:"When auditing complex formulas, what does the 'Trace Precedents' tool do?",opts:["It draws visual arrows indicating which cells affect the value of the currently selected cell","It finds the oldest value in the column","It draws arrows indicating which formulas depend on the active cell","It highlights syntax errors"],ans:0,exp:"The 'Trace Precedents' auditing tool maps out a formula's logical lineage. It displays blue tracer arrows pointing from the source data cells directly to the active formula cell. This visual mapping is absolutely crucial for financial analysts to debug large models and trace exactly where a formula is pulling its variables from."},hi:{q:"जटिल फ़ार्मुलों का ऑडिट करते समय, 'Trace Precedents' टूल क्या करता है?",opts:["यह दृश्य तीर खींचता है जो दर्शाता है कि कौन सी कोशिकाएँ वर्तमान में चयनित सेल के मान को प्रभावित करती हैं","यह कॉलम में सबसे पुराना मान ढूंढता है","यह तीर खींचता है जो दर्शाता है कि कौन से सूत्र सक्रिय सेल पर निर्भर करते हैं","यह सिंटैक्स त्रुटियों को उजागर करता है"],ans:0,exp:"'Trace Precedents' ऑडिटिंग टूल एक सूत्र के तार्किक वंश को मैप करता है। यह स्रोत डेटा सेल से सीधे सक्रिय फॉर्मूला सेल की ओर इशारा करते हुए नीले ट्रेसर तीर प्रदर्शित करता है। वित्तीय विश्लेषकों के लिए बड़े मॉडलों को डिबग करने और यह पता लगाने के लिए यह दृश्य मानचित्रण बिल्कुल महत्वपूर्ण है कि एक सूत्र अपने चर को कहाँ से खींच रहा है।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following describes Power Query in modern Excel?",opts:["A tool strictly for creating Macros","An advanced data connection, transformation, and shaping tool capable of combining millions of rows","A plugin for creating 3D pie charts","A security tool for encrypting cells"],ans:1,exp:"Power Query (Get & Transform Data) is a revolutionary ETL (Extract, Transform, Load) engine embedded in Excel. It connects to vast external data sources (SQL, web, CSVs), cleanses, reshapes, and merges massive datasets far exceeding Excel's 1-million-row limit, seamlessly loading the polished data directly into the Data Model or Pivot Tables."},hi:{q:"आधुनिक Excel में Power Query का वर्णन निम्नलिखित में से कौन करता है?",opts:["सख्ती से मैक्रोज़ बनाने के लिए एक टूल","एक उन्नत डेटा कनेक्शन, परिवर्तन, और आकार देने वाला उपकरण जो लाखों पंक्तियों के संयोजन में सक्षम है","3D पाई चार्ट बनाने के लिए एक प्लगइन","कोशिकाओं को एन्क्रिप्ट करने के लिए एक सुरक्षा उपकरण"],ans:1,exp:"पावर क्वेरी (डेटा प्राप्त करें और रूपांतरित करें) Excel में एम्बेडेड एक क्रांतिकारी ETL (एक्सट्रैक्ट, ट्रांसफॉर्म, लोड) इंजन है। यह विशाल बाहरी डेटा स्रोतों (SQL, वेब, CSVs) से जुड़ता है, Excel की 1-मिलियन-पंक्ति सीमा से अधिक विशाल डेटासेट को साफ करता है, फिर से आकार देता है और विलय करता है, निर्बाध रूप से पॉलिश किए गए डेटा को सीधे डेटा मॉडल या पिवट टेबल्स में लोड करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In MS Excel, what is the maximum number of nested IF() statements permitted in a single formula in modern versions (2007+)?",opts:["7","16","64","128"],ans:2,exp:"While Excel 2003 and earlier severely restricted logical nesting to a maximum of 7 levels, modern Excel versions (2007 and onwards) expanded the calculation engine to support up to 64 nested IF() statements. Despite this allowance, using the IFS() function or VLOOKUP is generally recommended over massive nesting to maintain readability."},hi:{q:"MS Excel में, आधुनिक संस्करणों (2007+) में एकल सूत्र में नेस्टेड IF() कथनों की अधिकतम संख्या कितनी है?",opts:["7","16","64","128"],ans:2,exp:"जबकि Excel 2003 और इससे पहले के तार्किक नेस्टिंग (logical nesting) को अधिकतम 7 स्तरों तक गंभीर रूप से प्रतिबंधित किया गया था, आधुनिक Excel संस्करणों (2007 और बाद के) ने 64 नेस्टेड IF() कथनों का समर्थन करने के लिए गणना इंजन का विस्तार किया। इस भत्ते के बावजूद, पठनीयता बनाए रखने के लिए बड़े पैमाने पर नेस्टिंग पर IFS() फ़ंक्शन या VLOOKUP का उपयोग करने की आमतौर पर सिफारिश की जाती है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the purpose of the 'Evaluate Formula' feature in the Formula Auditing group?",opts:["It generates a random value for the formula","It steps through a complex formula part-by-part to show how the final result is calculated","It translates formulas into VBA code","It automatically fixes logic errors"],ans:1,exp:"The 'Evaluate Formula' dialog box is an advanced debugging tool. It breaks down complex, multi-layered formulas into their constituent parts. By repeatedly clicking 'Evaluate', the user watches the calculation engine substitute cell references with actual values and resolve each nested function sequentially until the final output is determined."},hi:{q:"फ़ॉर्मूला ऑडिटिंग समूह में 'Evaluate Formula' सुविधा का उद्देश्य क्या है?",opts:["यह सूत्र के लिए एक यादृच्छिक मान उत्पन्न करता है","यह दिखाने के लिए कि अंतिम परिणाम की गणना कैसे की जाती है, यह एक जटिल सूत्र को भाग-दर-भाग आगे बढ़ाता है","यह फ़ार्मुलों का VBA कोड में अनुवाद करता है","यह तर्क त्रुटियों को स्वचालित रूप से ठीक करता है"],ans:1,exp:"'एवैल्यूएट फॉर्मूला' डायलॉग बॉक्स एक उन्नत डिबगिंग टूल है। यह जटिल, बहु-स्तरीय फ़ार्मुलों को उनके घटक भागों में तोड़ देता है। बार-बार 'मूल्यांकन' पर क्लिक करके, उपयोगकर्ता गणना इंजन को सेल संदर्भों को वास्तविक मूल्यों के साथ प्रतिस्थापित करता है और अंतिम आउटपुट निर्धारित होने तक प्रत्येक नेस्टेड फ़ंक्शन को क्रमिक रूप से हल करता है।"}},
{type:"mcq",diff:"hard",en:{q:"When setting an Advanced Filter in Excel, what is the prerequisite for the 'Criteria Range'?",opts:["It must contain the same column headers as the source data table","It must be located on a completely different workbook","It must only contain numbers","It must be formatted as a Pivot Table"],ans:0,exp:"Unlike the standard AutoFilter, an Advanced Filter requires a dedicated physical 'Criteria Range' mapped out on the worksheet. The absolute prerequisite is that the top row of this criteria range must identically match the spelling of the column headers in the source dataset, allowing Excel to logically link the criteria to the correct columns."},hi:{q:"Excel में एक उन्नत फ़िल्टर (Advanced Filter) सेट करते समय, 'Criteria Range' के लिए क्या पूर्वापेक्षा है?",opts:["इसमें स्रोत डेटा तालिका के समान कॉलम हेडर होने चाहिए","यह पूरी तरह से अलग वर्कबुक पर स्थित होना चाहिए","इसमें केवल संख्याएँ होनी चाहिए","इसे एक पिवट टेबल के रूप में स्वरूपित किया जाना चाहिए"],ans:0,exp:"मानक AutoFilter के विपरीत, एक उन्नत फ़िल्टर को वर्कशीट पर मैप किए गए एक समर्पित भौतिक 'मानदंड सीमा (Criteria Range)' की आवश्यकता होती है। पूर्ण पूर्वापेक्षा यह है कि इस मानदंड सीमा की शीर्ष पंक्ति को स्रोत डेटासेट में कॉलम हेडर की वर्तनी से समान रूप से मेल खाना चाहिए, जिससे Excel तार्किक रूप से मानदंड को सही कॉलम से जोड़ सके।"}},
{type:"tf",diff:"hard",en:{q:"Macros recorded in Microsoft Excel are translated and stored as VBA (Visual Basic for Applications) code.",opts:["True","False"],ans:0,exp:"True. The Macro Recorder functions by translating human user interactions (clicks, typing, formatting) into syntactically correct VBA programming code. Advanced users can open the Visual Basic Editor (VBE) to manually read, edit, optimize, or write this underlying VBA code from scratch to execute incredibly complex automations."},hi:{q:"Microsoft Excel में रिकॉर्ड किए गए मैक्रोज़ का अनुवाद किया जाता है और VBA (एप्लिकेशन के लिए विज़ुअल बेसिक) कोड के रूप में संग्रहीत किया जाता है।",opts:["सही","गलत"],ans:0,exp:"सही। मैक्रो रिकॉर्डर मानव उपयोगकर्ता इंटरैक्शन (क्लिक, टाइपिंग, स्वरूपण) को वाक्यात्मक रूप से सही VBA प्रोग्रामिंग कोड में अनुवाद करके कार्य करता है। उन्नत उपयोगकर्ता इस अंतर्निहित VBA कोड को खरोंच से पढ़ने, संपादित करने, अनुकूलित करने या लिखने के लिए विजुअल बेसिक एडिटर (VBE) खोल सकते हैं ताकि अविश्वसनीय रूप से जटिल स्वचालन निष्पादित किया जा सके।"}},
{type:"tf",diff:"hard",en:{q:"The Advanced Excel tool 'Power BI' is completely unrelated to data visualization and is used exclusively for text formatting.",opts:["True","False"],ans:1,exp:"False. As noted in the NCVT syllabus module, Power BI is deeply integrated with Excel's data stack specifically for complex data modeling and producing rich, interactive visual dashboards. It is far beyond a simple text formatter, acting as Microsoft's flagship enterprise business intelligence and data visualization suite."},hi:{q:"उन्नत Excel टूल 'Power BI' डेटा विज़ुअलाइज़ेशन से पूरी तरह से असंबंधित है और इसका उपयोग विशेष रूप से टेक्स्ट स्वरूपण के लिए किया जाता है।",opts:["सही","गलत"],ans:1,exp:"गलत। जैसा कि NCVT पाठ्यक्रम मॉड्यूल में उल्लेख किया गया है, Power BI को विशेष रूप से जटिल डेटा मॉडलिंग और समृद्ध, इंटरैक्टिव विज़ुअल डैशबोर्ड बनाने के लिए Excel के डेटा स्टैक के साथ गहराई से एकीकृत किया गया है। यह एक साधारण टेक्स्ट फ़ॉर्मेटर से बहुत परे है, जो Microsoft के प्रमुख उद्यम व्यापार खुफिया और डेटा विज़ुअलाइज़ेशन सूट के रूप में कार्य करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which file extension is mandatory to save a modern MS Excel workbook that contains customized VBA macros?",opts:[".xlsx",".xlsm",".xlsb",".xltx"],ans:1,exp:"In modern Excel (2007 onwards), a standard .xlsx file cannot store VBA macro code due to security protocols. To save and execute macros, the workbook must be explicitly saved with the '.xlsm' (Excel Macro-Enabled Workbook) extension. This distinguishes safe, macro-free files from those containing potentially executable code."},hi:{q:"आधुनिक MS Excel वर्कबुक को सहेजने के लिए कौन सा फ़ाइल एक्सटेंशन अनिवार्य है जिसमें कस्टमाइज़ किए गए VBA मैक्रोज़ होते हैं?",opts:[".xlsx",".xlsm",".xlsb",".xltx"],ans:1,exp:"आधुनिक Excel (2007 के बाद) में, एक मानक .xlsx फ़ाइल सुरक्षा प्रोटोकॉल के कारण VBA मैक्रो कोड संग्रहीत नहीं कर सकती है। मैक्रोज़ को सहेजने और निष्पादित करने के लिए, वर्कबुक को '.xlsm' (Excel Macro-Enabled Workbook) एक्सटेंशन के साथ स्पष्ट रूप से सहेजा जाना चाहिए। यह सुरक्षित, मैक्रो-मुक्त फ़ाइलों को संभावित रूप से निष्पादन योग्य कोड वाली फ़ाइलों से अलग करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the primary characteristic of a 'Sparkline' in MS Excel?",opts:["It is a standalone 3D chart placed in a separate sheet","It is a miniature chart embedded within a single cell to show data trends","It is an animated transition between worksheets","It is a specific type of pie chart used for financial data"],ans:1,exp:"Introduced in Excel 2010, a Sparkline is a tiny, intense word-sized graphic or chart that resides entirely within a single worksheet cell. It provides a visual representation of data trends, such as seasonal increases or decreases, directly adjacent to its corresponding data, saving space and providing immediate context."},hi:{q:"MS Excel में 'स्पार्कलाइन' (Sparkline) की प्राथमिक विशेषता क्या है?",opts:["यह एक अलग शीट में रखा गया एक स्टैंडअलोन 3D चार्ट है","यह डेटा प्रवृत्तियों को दिखाने के लिए एकल सेल के भीतर एम्बेडेड एक लघु चार्ट है","यह वर्कशीट के बीच एक एनिमेटेड संक्रमण है","यह वित्तीय डेटा के लिए उपयोग किया जाने वाला एक विशिष्ट प्रकार का पाई चार्ट है"],ans:1,exp:"Excel 2010 में पेश किया गया, स्पार्कलाइन एक छोटा, तीव्र शब्द-आकार का ग्राफिक या चार्ट है जो पूरी तरह से एक वर्कशीट सेल के भीतर रहता है। यह डेटा प्रवृत्तियों का एक दृश्य प्रतिनिधित्व प्रदान करता है, जैसे मौसमी वृद्धि या कमी, सीधे इसके संबंधित डेटा के बगल में, अंतरिक्ष की बचत और तत्काल संदर्भ प्रदान करता है।"}},
{type:"mcq",diff:"hard",en:{q:"While 'Goal Seek' can alter only a single variable to achieve a target result, which Excel Add-in is used to find optimal solutions by changing multiple variables subject to constraints?",opts:["Scenario Manager","Data Table","Solver","Analysis ToolPak"],ans:2,exp:"The 'Solver' add-in is a powerful optimization tool in Excel used for advanced What-If Analysis. Unlike Goal Seek, which can only modify one input cell, Solver can adjust multiple variable cells simultaneously to maximize, minimize, or reach a specific target value, while strictly adhering to user-defined constraints and limits."},hi:{q:"जबकि 'गोल सीक' (Goal Seek) एक लक्ष्य परिणाम प्राप्त करने के लिए केवल एक चर (variable) को बदल सकता है, किस Excel Add-in का उपयोग बाधाओं (constraints) के अधीन कई चर को बदलकर इष्टतम समाधान खोजने के लिए किया जाता है?",opts:["Scenario Manager","Data Table","Solver","Analysis ToolPak"],ans:2,exp:"'सोल्वर' (Solver) ऐड-इन Excel में एक शक्तिशाली अनुकूलन उपकरण है जिसका उपयोग उन्नत व्हाट-इफ विश्लेषण के लिए किया जाता है। गोल सीक के विपरीत, जो केवल एक इनपुट सेल को संशोधित कर सकता है, सोल्वर उपयोगकर्ता द्वारा परिभाषित बाधाओं और सीमाओं का कड़ाई से पालन करते हुए, एक विशिष्ट लक्ष्य मूल्य को अधिकतम, न्यूनतम या तक पहुंचने के लिए एक साथ कई चर (variable) कोशिकाओं को समायोजित कर सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which function is used to convert a vertical range of cells into a horizontal range (or vice-versa), and historically required the Ctrl+Shift+Enter keystroke array execution?",opts:["CONVERT()","TRANSPOSE()","REVERSE()","INVERT()"],ans:1,exp:"The TRANSPOSE() function reorganizes data by flipping its orientation; it shifts vertical data along columns into horizontal data across rows, and vice versa. In legacy Excel versions, because it returns an array of values across multiple cells, it had to be committed as an Array Formula using Ctrl+Shift+Enter."},hi:{q:"किस फ़ंक्शन का उपयोग कोशिकाओं की लंबवत श्रेणी को क्षैतिज श्रेणी (या इसके विपरीत) में बदलने के लिए किया जाता है, और ऐतिहासिक रूप से Ctrl+Shift+Enter कीस्ट्रोक सरणी (array) निष्पादन की आवश्यकता होती है?",opts:["CONVERT()","TRANSPOSE()","REVERSE()","INVERT()"],ans:1,exp:"TRANSPOSE() फ़ंक्शन अपने अभिविन्यास (orientation) को फ़्लिप करके डेटा को पुनर्गठित करता है; यह कॉलम के साथ लंबवत डेटा को पंक्तियों के पार क्षैतिज डेटा में बदलता है, और इसके विपरीत। पुराने Excel संस्करणों में, क्योंकि यह कई कोशिकाओं में मानों की एक सरणी (array) देता है, इसे Ctrl+Shift+Enter का उपयोग करके ऐरे फॉर्मूला के रूप में प्रतिबद्ध किया जाना था।"}},
{type:"mcq",diff:"hard",en:{q:"Which undocumented Excel function is specifically used to calculate the exact number of days, months, or years between two given dates?",opts:["DATEDIF()","NETWORKDAYS()","YEARFRAC()","DAYS360()"],ans:0,exp:"The DATEDIF() function calculates the difference between two dates in days, months, or years, depending on the specified unit argument (like 'Y', 'M', or 'D'). Originally provided for Lotus 1-2-3 compatibility, it remains largely undocumented in Excel's function wizard but is highly effective for age calculations or tenure tracking."},hi:{q:"कौन सा अनिर्दिष्ट (undocumented) Excel फ़ंक्शन विशेष रूप से दो दी गई तिथियों के बीच दिनों, महीनों या वर्षों की सटीक संख्या की गणना करने के लिए उपयोग किया जाता है?",opts:["DATEDIF()","NETWORKDAYS()","YEARFRAC()","DAYS360()"],ans:0,exp:"DATEDIF() फ़ंक्शन निर्दिष्ट इकाई तर्क ('Y', 'M', या 'D' की तरह) के आधार पर दिनों, महीनों या वर्षों में दो तिथियों के बीच के अंतर की गणना करता है। मूल रूप से Lotus 1-2-3 संगतता के लिए प्रदान किया गया, यह Excel के फ़ंक्शन विज़ार्ड में काफी हद तक अनिर्दिष्ट रहता है, लेकिन आयु गणना या कार्यकाल ट्रैकिंग के लिए अत्यधिक प्रभावी है।"}},
{type:"mcq",diff:"hard",en:{q:"Which function acts as an index-based lookup, returning a value from a list based on a given position number, often serving as a cleaner alternative to nested IFs?",opts:["INDEX()","MATCH()","CHOOSE()","LOOKUP()"],ans:2,exp:"The CHOOSE() function selects and returns a value from a provided list of arguments based on an index number. For example, =CHOOSE(2, 'Red', 'Blue', 'Green') will return 'Blue'. It is frequently utilized in financial modeling and scenario building to elegantly switch between different sets of assumptions without complex IF nesting."},hi:{q:"कौन सा फ़ंक्शन इंडेक्स-आधारित लुकअप के रूप में कार्य करता है, दी गई स्थिति संख्या के आधार पर सूची से एक मान लौटाता है, अक्सर नेस्टेड IFs के एक स्वच्छ विकल्प के रूप में काम करता है?",opts:["INDEX()","MATCH()","CHOOSE()","LOOKUP()"],ans:2,exp:"CHOOSE() फ़ंक्शन एक इंडेक्स नंबर के आधार पर तर्कों की प्रदान की गई सूची से एक मान का चयन करता है और लौटाता है। उदाहरण के लिए, =CHOOSE(2, 'Red', 'Blue', 'Green') 'Blue' लौटाएगा। जटिल IF नेस्टिंग के बिना मान्यताओं के विभिन्न सेटों के बीच शानदार ढंग से स्विच करने के लिए वित्तीय मॉडलिंग और परिदृश्य निर्माण में इसका अक्सर उपयोग किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"In Data Validation, if you want to prevent a user from entering duplicate values in a column (e.g., Column A), which formula should be used in the 'Custom' rule?",opts:["=COUNTIF(A:A, A1)=1","=SUM(A:A, A1)=0","=MATCH(A1, A:A)=1","=VLOOKUP(A1, A:A, 1, FALSE)"],ans:0,exp:"To prevent duplicate entries via Data Validation, you use the COUNTIF() function within a Custom rule. The formula '=COUNTIF(A:A, A1)=1' continuously counts how many times the entered value appears in the entire column. If it appears more than once, the condition evaluates to FALSE, triggering an error alert and blocking the duplicate entry."},hi:{q:"डेटा सत्यापन (Data Validation) में, यदि आप किसी उपयोगकर्ता को कॉलम (उदा., कॉलम A) में डुप्लिकेट मान दर्ज करने से रोकना चाहते हैं, तो 'कस्टम' नियम में किस सूत्र का उपयोग किया जाना चाहिए?",opts:["=COUNTIF(A:A, A1)=1","=SUM(A:A, A1)=0","=MATCH(A1, A:A)=1","=VLOOKUP(A1, A:A, 1, FALSE)"],ans:0,exp:"डेटा सत्यापन के माध्यम से डुप्लिकेट प्रविष्टियों को रोकने के लिए, आप एक कस्टम नियम के भीतर COUNTIF() फ़ंक्शन का उपयोग करते हैं। सूत्र '=COUNTIF(A:A, A1)=1' लगातार गिनता है कि दर्ज किया गया मान पूरे कॉलम में कितनी बार दिखाई देता है। यदि यह एक से अधिक बार प्रकट होता है, तो स्थिति FALSE का मूल्यांकन करती है, एक त्रुटि चेतावनी को ट्रिगर करती है और डुप्लिकेट प्रविष्टि को अवरुद्ध करती है।"}},
{type:"mcq",diff:"hard",en:{q:"In a Pivot Table, what is a 'Calculated Field'?",opts:["A field that automatically generates a macro","A new data field created by applying mathematical formulas to existing fields within the Pivot Table","A summary function that counts blank cells","A field that connects to an external SQL database"],ans:1,exp:"A 'Calculated Field' is a custom field inserted directly into a Pivot Table that generates new data by performing mathematical operations on the existing data fields. Instead of modifying the raw source data table, users can dynamically create custom metrics (like calculating 'Profit' by subtracting 'Costs' from 'Revenue' fields) directly inside the Pivot Table environment."},hi:{q:"पिवट टेबल में, 'कैलकुलेटेड फील्ड' (Calculated Field) क्या है?",opts:["एक फ़ील्ड जो स्वचालित रूप से मैक्रो उत्पन्न करता है","पिवट टेबल के भीतर मौजूदा फ़ील्ड में गणितीय सूत्र लागू करके बनाया गया एक नया डेटा फ़ील्ड","एक सारांश फ़ंक्शन जो खाली सेल की गणना करता है","एक फ़ील्ड जो बाहरी SQL डेटाबेस से जुड़ता है"],ans:1,exp:"'कैलकुलेटेड फील्ड' सीधे पिवट टेबल में डाला गया एक कस्टम फ़ील्ड है जो मौजूदा डेटा फ़ील्ड पर गणितीय संचालन करके नया डेटा उत्पन्न करता है। कच्चे स्रोत डेटा तालिका को संशोधित करने के बजाय, उपयोगकर्ता पिवट टेबल वातावरण के अंदर सीधे कस्टम मैट्रिक्स (जैसे 'राजस्व' क्षेत्रों से 'लागत' घटाकर 'लाभ' की गणना) बना सकते हैं।"}}
];

